#[test]
fn apply_runtime_closure_sees_rules_driven_ambient_state() {
    set_current_transaction_rules(None);
    set_st_number_switchover(true);

    let rules = Rules::new([feature_universal_number()]);
    let observed = with_transaction_apply_runtime(&rules, || {
        (
            get_current_transaction_rules(),
            get_st_number_switchover(),
            get_mantissa_scale(),
        )
    });

    assert_eq!(observed, (Some(rules), true, MantissaScale::Small));
    assert_eq!(get_current_transaction_rules(), None);
    assert!(get_st_number_switchover());
    assert_eq!(get_mantissa_scale(), MantissaScale::Large);
}

#[test]
fn apply_runtime_restores_prior_ambient_state_after_closure() {
    let original = Rules::new([feature_single_asset_vault()]);
    set_current_transaction_rules(Some(original.clone()));
    set_st_number_switchover(false);

    let replacement = Rules::new([feature_universal_number()]);
    with_transaction_apply_runtime(&replacement, || {
        assert_eq!(get_current_transaction_rules(), Some(replacement.clone()));
        assert!(get_st_number_switchover());
        assert_eq!(get_mantissa_scale(), MantissaScale::Small);
    });

    assert_eq!(get_current_transaction_rules(), Some(original));
    assert!(!get_st_number_switchover());
    assert_eq!(get_mantissa_scale(), MantissaScale::Large);
    set_current_transaction_rules(None);
    set_st_number_switchover(true);
}

