#[test]
fn txq_sequence_position_rule_matches_current_cpp_queue_entry_checks() {
    let mut front_ticket = TxQAccount::new("acct");
    front_ticket.add(
        SeqProxy::ticket(2),
        MaybeTxCore::new("ticket", TxConsequences::new(1, SeqProxy::ticket(2))),
    );

    assert_eq!(
        check_sequence_position(
            &front_ticket,
            SeqProxy::sequence(4),
            SeqProxy::sequence(5),
            false,
        ),
        Ter::TEF_PAST_SEQ
    );
    assert_eq!(
        check_sequence_position(
            &front_ticket,
            SeqProxy::sequence(6),
            SeqProxy::sequence(5),
            false,
        ),
        Ter::TER_PRE_SEQ
    );

    let mut queued = TxQAccount::new("acct");
    queued.add(
        SeqProxy::sequence(5),
        MaybeTxCore::new(
            "s5",
            TxConsequences::with_sequences_consumed(1, SeqProxy::sequence(5), 1),
        ),
    );
    queued.add(
        SeqProxy::sequence(7),
        MaybeTxCore::new(
            "s7",
            TxConsequences::with_sequences_consumed(1, SeqProxy::sequence(7), 1),
        ),
    );

    assert_eq!(
        check_sequence_position(&queued, SeqProxy::sequence(8), SeqProxy::sequence(5), false),
        Ter::TEL_CAN_NOT_QUEUE
    );
    assert_eq!(
        check_sequence_position(&queued, SeqProxy::sequence(8), SeqProxy::sequence(5), true),
        Ter::TES_SUCCESS
    );
}

