fn build_closed_ledger_maybe_tx(
    tx: &'static str,
    account: &'static str,
    seq_proxy: SeqProxy,
    tx_id: u64,
    fee_level: u64,
    last_valid: Option<u32>,
) -> MaybeTx<&'static str, &'static str, &'static str, &'static str> {
    MaybeTx::new(
        Uint256::from_u64(tx_id),
        fee_level,
        account,
        last_valid,
        seq_proxy,
        ApplyFlags::NONE,
        PreflightResult::new(
            tx,
            None::<&str>,
            Rules::new(std::iter::empty()),
            TxConsequences::new(1, seq_proxy),
            ApplyFlags::NONE,
            "journal",
            Ter::TES_SUCCESS,
        ),
    )
}

fn build_process_closed_ledger_public_txq()
-> QueueAcceptTxQ<&'static str, &'static str, &'static str, &'static str, ParityAcceptJournal> {
    let mut keep = TxQAccount::new("keep");
    keep.add(
        SeqProxy::sequence(5),
        MaybeTxCore::new(
            build_closed_ledger_maybe_tx(
                "expired-keep",
                "keep",
                SeqProxy::sequence(5),
                5,
                300,
                Some(20),
            ),
            TxConsequences::new(1, SeqProxy::sequence(5)),
        ),
    );
    keep.add(
        SeqProxy::sequence(6),
        MaybeTxCore::new(
            build_closed_ledger_maybe_tx(
                "live-keep",
                "keep",
                SeqProxy::sequence(6),
                6,
                250,
                Some(21),
            ),
            TxConsequences::new(1, SeqProxy::sequence(6)),
        ),
    );

    let mut drop = TxQAccount::new("drop");
    drop.add(
        SeqProxy::sequence(9),
        MaybeTxCore::new(
            build_closed_ledger_maybe_tx(
                "expired-drop",
                "drop",
                SeqProxy::sequence(9),
                9,
                150,
                Some(20),
            ),
            TxConsequences::new(1, SeqProxy::sequence(9)),
        ),
    );

    QueueAcceptTxQ::new(QueueAcceptLockScopeOwner::new(
        QueueAcceptJournalOwner::new(
            QueueAcceptOwnerShell::new(QueueAcceptLiveOwner::new(
                QueueFeeMetricsState::new(QueueFeeMetricsConfig {
                    ledgers_in_queue: 3,
                    queue_size_min: 20,
                    minimum_escalation_multiplier: TXQ_BASE_LEVEL * 500,
                    minimum_txn_in_ledger: 32,
                    target_txn_in_ledger: 256,
                    maximum_txn_in_ledger: Some(400),
                    normal_consensus_increase_percent: 20,
                    slow_consensus_decrease_percent: 50,
                }),
                Some(50),
                QueueAcceptOwnerState::new(Uint256::from_u64(9)),
                QueueViews::new(
                    std::collections::BTreeMap::from([("drop", drop), ("keep", keep)]),
                    vec![
                        FeeQueueEntry::new(
                            FeeQueueKey::new("keep", SeqProxy::sequence(5)),
                            QueueAdvanceCandidate {
                                fee_level: 300,
                                tx_id: Uint256::from_u64(5),
                                seq_proxy: SeqProxy::sequence(5),
                            },
                        ),
                        FeeQueueEntry::new(
                            FeeQueueKey::new("keep", SeqProxy::sequence(6)),
                            QueueAdvanceCandidate {
                                fee_level: 250,
                                tx_id: Uint256::from_u64(6),
                                seq_proxy: SeqProxy::sequence(6),
                            },
                        ),
                        FeeQueueEntry::new(
                            FeeQueueKey::new("drop", SeqProxy::sequence(9)),
                            QueueAdvanceCandidate {
                                fee_level: 150,
                                tx_id: Uint256::from_u64(9),
                                seq_proxy: SeqProxy::sequence(9),
                            },
                        ),
                    ],
                ),
            )),
            ParityAcceptJournal::default(),
        ),
    ))
}

#[test]
fn txq_process_closed_ledger_public_boundary_updates_metrics_and_owner_views() {
    let mut txq = build_process_closed_ledger_public_txq();
    let app = ParityClosedLedgerAppSource {
        validated_fee_levels: vec![TXQ_BASE_LEVEL * 600; 300],
    };
    let view = ParityClosedLedgerViewSource { ledger_seq: 20 };
    let mut lock = ParityAcceptLockScope;

    let result = txq.process_closed_ledger(&mut lock, &app, &view, false);

    assert_eq!(
        result,
        ClosedLedgerMaintenanceWithMetrics {
            validated_tx_count: 300,
            metrics_snapshot: QueueFeeMetricsSnapshot {
                txns_expected: 360,
                escalation_multiplier: TXQ_BASE_LEVEL * 600,
            },
            maintenance: ClosedLedgerMaintenance {
                next_max_size: 1080,
                expired_candidates: vec![
                    ClosedLedgerCandidate {
                        account: "keep",
                        seq_proxy: SeqProxy::sequence(5),
                        last_valid: Some(20),
                    },
                    ClosedLedgerCandidate {
                        account: "drop",
                        seq_proxy: SeqProxy::sequence(9),
                        last_valid: Some(20),
                    },
                ],
                emptied_accounts: vec!["drop"],
            },
        }
    );

    let live_owner = txq.lock_scope_owner().owner().owner().owner();
    assert_eq!(live_owner.current_max_size(), Some(1080));
    assert_eq!(
        live_owner
            .views()
            .fee_order
            .iter()
            .map(|entry| entry.key.clone())
            .collect::<Vec<_>>(),
        vec![FeeQueueKey::new("keep", SeqProxy::sequence(6))]
    );
    assert!(!live_owner.views().accounts.contains_key("drop"));
    let keep_account = live_owner
        .views()
        .accounts
        .get("keep")
        .expect("keep account should remain");
    assert!(keep_account.drop_penalty);
    assert!(
        keep_account
            .transactions
            .contains_key(&SeqProxy::sequence(6))
    );
}

