fn txq_accept_gate_skips_later_sequence_candidates_and_stops_on_fee_threshold() {
    assert_eq!(
        evaluate_accept_candidate(SeqProxy::sequence(7), SeqProxy::sequence(5), 100, 90),
        AcceptCandidateGate::SkipNotFirst
    );
    assert_eq!(
        evaluate_accept_candidate(SeqProxy::sequence(5), SeqProxy::sequence(5), 89, 90),
        AcceptCandidateGate::StopInsufficientFee
    );
    assert_eq!(
        evaluate_accept_candidate(SeqProxy::sequence(5), SeqProxy::sequence(5), 90, 90),
        AcceptCandidateGate::TryApply
    );
    assert_eq!(
        evaluate_accept_candidate(SeqProxy::ticket(9), SeqProxy::sequence(5), 90, 90),
        AcceptCandidateGate::TryApply
    );
}

#[test]
fn txq_accept_iteration_drops_the_last_account_item_on_near_full_soft_failure() {
    let queued = |account: &'static str,
                  seq_proxy: SeqProxy,
                  tx_id: u64,
                  fee_level: u64|
     -> MaybeTx<&'static str, &'static str, &'static str, &'static str> {
        MaybeTx::new(
            Uint256::from_u64(tx_id),
            fee_level,
            account,
            Some(200),
            seq_proxy,
            ApplyFlags::NONE,
            PreflightResult::new(
                "tx",
                None::<&str>,
                Rules::new(std::iter::empty()),
                TxConsequences::new(1, seq_proxy),
                ApplyFlags::NONE,
                "journal",
                Ter::TES_SUCCESS,
            ),
        )
    };

    let mut account_a = TxQAccount::new("a");
    account_a.drop_penalty = true;
    account_a.add(
        SeqProxy::sequence(5),
        MaybeTxCore::new(
            queued("a", SeqProxy::sequence(5), 5, 100),
            TxConsequences::new(1, SeqProxy::sequence(5)),
        ),
    );
    account_a.add(
        SeqProxy::sequence(9),
        MaybeTxCore::new(
            queued("a", SeqProxy::sequence(9), 9, 60),
            TxConsequences::new(1, SeqProxy::sequence(9)),
        ),
    );

    let mut account_b = TxQAccount::new("b");
    account_b.add(
        SeqProxy::sequence(7),
        MaybeTxCore::new(
            queued("b", SeqProxy::sequence(7), 7, 95),
            TxConsequences::new(1, SeqProxy::sequence(7)),
        ),
    );

    let mut views = QueueViews::new(
        std::collections::BTreeMap::from([("a", account_a), ("b", account_b)]),
        vec![
            FeeQueueEntry::new(
                FeeQueueKey::new("a", SeqProxy::sequence(5)),
                QueueAdvanceCandidate {
                    fee_level: 100,
                    tx_id: Uint256::from_u64(5),
                    seq_proxy: SeqProxy::sequence(5),
                },
            ),
            FeeQueueEntry::new(
                FeeQueueKey::new("b", SeqProxy::sequence(7)),
                QueueAdvanceCandidate {
                    fee_level: 95,
                    tx_id: Uint256::from_u64(7),
                    seq_proxy: SeqProxy::sequence(7),
                },
            ),
            FeeQueueEntry::new(
                FeeQueueKey::new("a", SeqProxy::sequence(9)),
                QueueAdvanceCandidate {
                    fee_level: 60,
                    tx_id: Uint256::from_u64(9),
                    seq_proxy: SeqProxy::sequence(9),
                },
            ),
        ],
    );

    let iteration = run_queue_accept_iteration(
        &mut views,
        &FeeQueueKey::new("a", SeqProxy::sequence(5)),
        80,
        true,
        &OrderCandidates::new(Uint256::from_u64(0)),
        |_queued| ApplyResult::new(Ter::TER_RETRY, false, false),
    );

    assert_eq!(
        iteration,
        QueueAcceptIteration::RetainedFailed {
            candidate: QueueAcceptCandidate {
                key: FeeQueueKey::new("a", SeqProxy::sequence(5)),
                tx_id: Uint256::from_u64(5),
                fee_level: 100,
                retries_remaining: MAYBE_TX_RETRIES_ALLOWED,
                flags: ApplyFlags::NONE,
            },
            txn_result: Ter::TER_RETRY,
            next_retries_remaining: MAYBE_TX_RETRIES_ALLOWED - 1,
            dropped_last_from_account: true,
            removed_tail: Some(FeeQueueKey::new("a", SeqProxy::sequence(9))),
            next_candidate: Some(FeeQueueKey::new("b", SeqProxy::sequence(7))),
        }
    );
    assert_eq!(
        views.accounts["a"].transactions[&SeqProxy::sequence(5)]
            .payload
            .last_result,
        Some(Ter::TER_RETRY)
    );
    assert!(
        !views.accounts["a"]
            .transactions
            .contains_key(&SeqProxy::sequence(9))
    );
}

