#[test]
fn txq_accept_call_envelope_sink_wrapper_matches_owner_shell_sink_call_boundary() {
    let queued = |account: &'static str,
                  seq_proxy: SeqProxy,
                  tx_id: u64,
                  fee_level: u64|
     -> MaybeTx<&'static str, &'static str, &'static str, &'static str> {
        MaybeTx::new(
            Uint256::from_u64(tx_id),
            fee_level,
            account,
            Some(200),
            seq_proxy,
            ApplyFlags::NONE,
            PreflightResult::new(
                "tx",
                None::<&str>,
                Rules::new(std::iter::empty()),
                TxConsequences::new(1, seq_proxy),
                ApplyFlags::NONE,
                "journal",
                Ter::TES_SUCCESS,
            ),
        )
    };

    let build_views = || {
        let mut account = TxQAccount::new("acct");
        account.drop_penalty = true;
        account.add(
            SeqProxy::sequence(5),
            MaybeTxCore::new(
                queued("acct", SeqProxy::sequence(5), 5, 300),
                TxConsequences::new(1, SeqProxy::sequence(5)),
            ),
        );
        account.add(
            SeqProxy::sequence(9),
            MaybeTxCore::new(
                queued("acct", SeqProxy::sequence(9), 9, 60),
                TxConsequences::new(1, SeqProxy::sequence(9)),
            ),
        );

        QueueViews::new(
            std::collections::BTreeMap::from([("acct", account)]),
            vec![
                FeeQueueEntry::new(
                    FeeQueueKey::new("acct", SeqProxy::sequence(5)),
                    QueueAdvanceCandidate {
                        fee_level: 300,
                        tx_id: Uint256::from_u64(5),
                        seq_proxy: SeqProxy::sequence(5),
                    },
                ),
                FeeQueueEntry::new(
                    FeeQueueKey::new("acct", SeqProxy::sequence(9)),
                    QueueAdvanceCandidate {
                        fee_level: 60,
                        tx_id: Uint256::from_u64(9),
                        seq_proxy: SeqProxy::sequence(9),
                    },
                ),
            ],
        )
    };

    let metrics = QueueFeeMetricsState::new(QueueFeeMetricsConfig {
        ledgers_in_queue: 3,
        queue_size_min: 20,
        minimum_escalation_multiplier: TXQ_BASE_LEVEL * 500,
        minimum_txn_in_ledger: 32,
        target_txn_in_ledger: 256,
        maximum_txn_in_ledger: Some(400),
        normal_consensus_increase_percent: 20,
        slow_consensus_decrease_percent: 50,
    });
    let mut shell_app = ParityAcceptApplyOnlyApp {
        apply_result: ApplyResult::new(Ter::TER_RETRY, false, false),
        apply_calls: 0,
    };
    let mut envelope_app = ParityAcceptApplyOnlyApp {
        apply_result: ApplyResult::new(Ter::TER_RETRY, false, false),
        apply_calls: 0,
    };
    let view = ParityAcceptLedgerView {
        open_ledger_tx_count: 32,
        parent_hash: Uint256::from_u64(9),
    };

    let mut shell = QueueAcceptOwnerShell::new(QueueAcceptLiveOwner::new(
        metrics.clone(),
        Some(2),
        QueueAcceptOwnerState::new(Uint256::from_u64(9)),
        build_views(),
    ));
    let shell_emitted = RefCell::new(Vec::new());
    let shell_result = shell.accept_with_log_sinks(
        &mut shell_app,
        &view,
        |message| shell_emitted.borrow_mut().push(format!("trace:{message}")),
        |message| shell_emitted.borrow_mut().push(format!("debug:{message}")),
        |message| shell_emitted.borrow_mut().push(format!("info:{message}")),
        |message| shell_emitted.borrow_mut().push(format!("warn:{message}")),
    );

    let mut envelope_shell = QueueAcceptOwnerShell::new(QueueAcceptLiveOwner::new(
        metrics,
        Some(2),
        QueueAcceptOwnerState::new(Uint256::from_u64(9)),
        build_views(),
    ));
    let envelope_emitted = RefCell::new(Vec::new());
    let mut envelope = QueueAcceptCallEnvelope::new(&mut envelope_app, &view);
    let envelope_result = envelope.accept_with_log_sinks(
        &mut envelope_shell,
        |message| {
            envelope_emitted
                .borrow_mut()
                .push(format!("trace:{message}"))
        },
        |message| {
            envelope_emitted
                .borrow_mut()
                .push(format!("debug:{message}"))
        },
        |message| {
            envelope_emitted
                .borrow_mut()
                .push(format!("info:{message}"))
        },
        |message| {
            envelope_emitted
                .borrow_mut()
                .push(format!("warn:{message}"))
        },
    );

    assert_eq!(envelope_result, shell_result);
    assert_eq!(envelope_shell.owner(), shell.owner());
    assert_eq!(envelope_emitted.into_inner(), shell_emitted.into_inner());
    assert_eq!(shell_app.apply_calls, 1);
    assert_eq!(envelope_app.apply_calls, 1);
}

