#[test]
fn txq_erase_range_removes_half_open_account_ranges_and_returns_next_key() {
    let mut account = TxQAccount::new("acct");
    account.add(
        SeqProxy::sequence(5),
        MaybeTxCore::new("s5", TxConsequences::new(1, SeqProxy::sequence(5))),
    );
    account.add(
        SeqProxy::sequence(6),
        MaybeTxCore::new("s6", TxConsequences::new(1, SeqProxy::sequence(6))),
    );
    account.add(
        SeqProxy::sequence(8),
        MaybeTxCore::new("s8", TxConsequences::new(1, SeqProxy::sequence(8))),
    );

    let result = erase_account_range(
        &mut account,
        SeqProxy::sequence(5),
        Some(SeqProxy::sequence(8)),
    );

    assert_eq!(
        result.removed_seq_proxies,
        vec![SeqProxy::sequence(5), SeqProxy::sequence(6)]
    );
    assert_eq!(result.next_seq_proxy, Some(SeqProxy::sequence(8)));
    assert_eq!(account.get_txn_count(), 1);
    assert!(account.transactions.contains_key(&SeqProxy::sequence(8)));
}

#[test]
fn txq_erase_single_candidate_removes_fee_and_account_views() {
    let mut first = TxQAccount::new("a");
    first.add(
        SeqProxy::sequence(5),
        MaybeTxCore::new("a5", TxConsequences::new(1, SeqProxy::sequence(5))),
    );

    let mut second = TxQAccount::new("b");
    second.add(
        SeqProxy::sequence(7),
        MaybeTxCore::new("b7", TxConsequences::new(1, SeqProxy::sequence(7))),
    );

    let mut accounts = std::collections::BTreeMap::from([("a", first), ("b", second)]);
    let mut fee_order = vec![
        FeeQueueKey::new("a", SeqProxy::sequence(5)),
        FeeQueueKey::new("b", SeqProxy::sequence(7)),
    ];

    let result = erase_fee_candidate(&mut accounts, &mut fee_order, 0);

    assert_eq!(
        result,
        EraseCandidateResult {
            removed: FeeQueueKey::new("a", SeqProxy::sequence(5)),
            next_fee_candidate: Some(FeeQueueKey::new("b", SeqProxy::sequence(7))),
        }
    );
    assert_eq!(
        fee_order,
        vec![FeeQueueKey::new("b", SeqProxy::sequence(7))]
    );
    assert!(accounts.contains_key("a"));
    assert!(accounts.get("a").is_some_and(TxQAccount::empty));
}

#[test]
fn txq_queue_views_erase_and_advance_can_resume_same_account_candidate() {
    let mut account_a = TxQAccount::new("a");
    account_a.add(
        SeqProxy::sequence(5),
        MaybeTxCore::new("a5", TxConsequences::new(1, SeqProxy::sequence(5))),
    );
    account_a.add(
        SeqProxy::sequence(6),
        MaybeTxCore::new("a6", TxConsequences::new(1, SeqProxy::sequence(6))),
    );

    let mut account_b = TxQAccount::new("b");
    account_b.add(
        SeqProxy::sequence(7),
        MaybeTxCore::new("b7", TxConsequences::new(1, SeqProxy::sequence(7))),
    );

    let mut views = QueueViews::new(
        std::collections::BTreeMap::from([("a", account_a), ("b", account_b)]),
        vec![
            tx::FeeQueueEntry::new(
                FeeQueueKey::new("a", SeqProxy::sequence(6)),
                QueueAdvanceCandidate {
                    fee_level: 110,
                    tx_id: basics::base_uint::Uint256::from_u64(6),
                    seq_proxy: SeqProxy::sequence(6),
                },
            ),
            tx::FeeQueueEntry::new(
                FeeQueueKey::new("b", SeqProxy::sequence(7)),
                QueueAdvanceCandidate {
                    fee_level: 105,
                    tx_id: basics::base_uint::Uint256::from_u64(7),
                    seq_proxy: SeqProxy::sequence(7),
                },
            ),
            tx::FeeQueueEntry::new(
                FeeQueueKey::new("a", SeqProxy::sequence(5)),
                QueueAdvanceCandidate {
                    fee_level: 100,
                    tx_id: basics::base_uint::Uint256::from_u64(5),
                    seq_proxy: SeqProxy::sequence(5),
                },
            ),
        ],
    );

    let result = views.erase_and_advance(
        2,
        &OrderCandidates::new(basics::base_uint::Uint256::from_u64(0)),
    );

    assert_eq!(
        result,
        QueueEraseAdvanceResult {
            removed: FeeQueueKey::new("a", SeqProxy::sequence(5)),
            next: QueueViewNext::AccountNext(FeeQueueKey::new("a", SeqProxy::sequence(6))),
        }
    );
    assert_eq!(views.accounts["a"].get_txn_count(), 1);
    assert!(
        views.accounts["a"]
            .transactions
            .contains_key(&SeqProxy::sequence(6))
    );
}

