#[test]
fn txq_apply_enqueue_replaces_entry_strips_retry_and_returns_ter_queued() {
    let mut account_a = TxQAccount::new("a");
    account_a.add(
        SeqProxy::sequence(5),
        MaybeTxCore::new(
            MaybeTx::new(
                basics::base_uint::Uint256::from_u64(5),
                90,
                "a",
                Some(200),
                SeqProxy::sequence(5),
                ApplyFlags::RETRY,
                PreflightResult::new(
                    "old",
                    None::<&str>,
                    Rules::new(std::iter::empty()),
                    TxConsequences::new(1, SeqProxy::sequence(5)),
                    ApplyFlags::RETRY,
                    "journal",
                    Ter::TES_SUCCESS,
                ),
            ),
            TxConsequences::new(1, SeqProxy::sequence(5)),
        ),
    );

    let mut account_b = TxQAccount::new("b");
    account_b.add(
        SeqProxy::sequence(7),
        MaybeTxCore::new(
            MaybeTx::new(
                basics::base_uint::Uint256::from_u64(7),
                100,
                "b",
                None,
                SeqProxy::sequence(7),
                ApplyFlags::NONE,
                PreflightResult::new(
                    "other",
                    None::<&str>,
                    Rules::new(std::iter::empty()),
                    TxConsequences::new(1, SeqProxy::sequence(7)),
                    ApplyFlags::NONE,
                    "journal",
                    Ter::TES_SUCCESS,
                ),
            ),
            TxConsequences::new(1, SeqProxy::sequence(7)),
        ),
    );

    let mut views = QueueViews::new(
        std::collections::BTreeMap::from([("a", account_a), ("b", account_b)]),
        vec![
            FeeQueueEntry::new(
                FeeQueueKey::new("b", SeqProxy::sequence(7)),
                QueueAdvanceCandidate {
                    fee_level: 100,
                    tx_id: basics::base_uint::Uint256::from_u64(7),
                    seq_proxy: SeqProxy::sequence(7),
                },
            ),
            FeeQueueEntry::new(
                FeeQueueKey::new("a", SeqProxy::sequence(5)),
                QueueAdvanceCandidate {
                    fee_level: 90,
                    tx_id: basics::base_uint::Uint256::from_u64(5),
                    seq_proxy: SeqProxy::sequence(5),
                },
            ),
        ],
    );

    let result = enqueue_queue_apply_candidate(
        &mut views,
        Some(FeeQueueKey::new("a", SeqProxy::sequence(5))),
        "a",
        basics::base_uint::Uint256::from_u64(9),
        Some(250),
        SeqProxy::sequence(5),
        110,
        ApplyFlags::FAIL_HARD | ApplyFlags::RETRY,
        PreflightResult::new(
            "replacement",
            None::<&str>,
            Rules::new(std::iter::empty()),
            TxConsequences::new(2, SeqProxy::sequence(5)),
            ApplyFlags::FAIL_HARD | ApplyFlags::RETRY,
            "journal",
            Ter::TES_SUCCESS,
        ),
        &OrderCandidates::new(basics::base_uint::Uint256::from_u64(0)),
    );

    assert_eq!(
        result,
        QueueApplyEnqueueResult {
            queued: FeeQueueKey::new("a", SeqProxy::sequence(5)),
            removed_replacement: Some(FeeQueueKey::new("a", SeqProxy::sequence(5))),
            account_created: false,
            stored_flags: ApplyFlags::FAIL_HARD,
        }
    );
    assert_eq!(result.ter(), Ter::TER_QUEUED);
    assert_eq!(
        views
            .fee_order
            .iter()
            .map(|entry| entry.key.clone())
            .collect::<Vec<_>>(),
        vec![
            FeeQueueKey::new("a", SeqProxy::sequence(5)),
            FeeQueueKey::new("b", SeqProxy::sequence(7)),
        ]
    );
    assert_eq!(
        views.accounts["a"].transactions[&SeqProxy::sequence(5)]
            .payload
            .flags,
        ApplyFlags::FAIL_HARD
    );
}

#[test]
fn txq_direct_apply_eligibility_matches_current_cpp_gates() {
    assert_eq!(
        evaluate_direct_apply_eligibility(
            false,
            SeqProxy::sequence(5),
            SeqProxy::sequence(5),
            100,
            100,
        ),
        DirectApplyEligibility::MissingAccount
    );

    assert_eq!(
        evaluate_direct_apply_eligibility(
            true,
            SeqProxy::sequence(5),
            SeqProxy::sequence(6),
            100,
            100,
        ),
        DirectApplyEligibility::SequenceMismatch
    );

    assert_eq!(
        evaluate_direct_apply_eligibility(
            true,
            SeqProxy::sequence(5),
            SeqProxy::ticket(9),
            99,
            100,
        ),
        DirectApplyEligibility::InsufficientFee
    );

    assert_eq!(
        evaluate_direct_apply_eligibility(
            true,
            SeqProxy::sequence(5),
            SeqProxy::ticket(9),
            100,
            100,
        ),
        DirectApplyEligibility::Eligible
    );
}

#[test]
fn txq_direct_apply_finalization_matches_current_cpp_cleanup_boundary() {
    let mut account_a = TxQAccount::new("a");
    account_a.add(
        SeqProxy::sequence(5),
        MaybeTxCore::new("a5", TxConsequences::new(1, SeqProxy::sequence(5))),
    );

    let mut success_views = QueueViews::new(
        std::collections::BTreeMap::from([("a", account_a)]),
        vec![tx::FeeQueueEntry::new(
            FeeQueueKey::new("a", SeqProxy::sequence(5)),
            QueueAdvanceCandidate {
                fee_level: 100,
                tx_id: basics::base_uint::Uint256::from_u64(5),
                seq_proxy: SeqProxy::sequence(5),
            },
        )],
    );

    let success = finalize_direct_apply_attempt(
        &mut success_views,
        DirectApplyEligibility::Eligible,
        &"a",
        SeqProxy::sequence(5),
        ApplyResult::new(Ter::TES_SUCCESS, true, true),
    );

    assert_eq!(
        success,
        Some(DirectApplyAttemptResult {
            apply_result: ApplyResult::new(Ter::TES_SUCCESS, true, true),
            removed_replacement: Some(FeeQueueKey::new("a", SeqProxy::sequence(5))),
        })
    );
    assert!(success_views.fee_order.is_empty());
    assert!(success_views.accounts["a"].empty());

    let mut account_b = TxQAccount::new("a");
    account_b.add(
        SeqProxy::sequence(5),
        MaybeTxCore::new("a5", TxConsequences::new(1, SeqProxy::sequence(5))),
    );
    let mut failure_views = QueueViews::new(
        std::collections::BTreeMap::from([("a", account_b)]),
        vec![tx::FeeQueueEntry::new(
            FeeQueueKey::new("a", SeqProxy::sequence(5)),
            QueueAdvanceCandidate {
                fee_level: 100,
                tx_id: basics::base_uint::Uint256::from_u64(5),
                seq_proxy: SeqProxy::sequence(5),
            },
        )],
    );

    let failure = finalize_direct_apply_attempt(
        &mut failure_views,
        DirectApplyEligibility::Eligible,
        &"a",
        SeqProxy::sequence(5),
        ApplyResult::new(Ter::TEF_EXCEPTION, false, false),
    );

    assert_eq!(
        failure,
        Some(DirectApplyAttemptResult {
            apply_result: ApplyResult::new(Ter::TEF_EXCEPTION, false, false),
            removed_replacement: None,
        })
    );
    assert_eq!(failure_views.fee_order.len(), 1);
    assert_eq!(failure_views.accounts["a"].get_txn_count(), 1);

    let mut ineligible_views = QueueViews::<&str, &str>::default();
    let ineligible = finalize_direct_apply_attempt(
        &mut ineligible_views,
        DirectApplyEligibility::InsufficientFee,
        &"a",
        SeqProxy::sequence(5),
        ApplyResult::new(Ter::TES_SUCCESS, true, true),
    );
    assert_eq!(ineligible, None);
}

#[test]
fn txq_direct_apply_wrapper_only_invokes_apply_when_eligible() {
    let invoked = std::cell::Cell::new(0_u32);
    let mut success_account = TxQAccount::new("a");
    success_account.add(
        SeqProxy::sequence(5),
        MaybeTxCore::new("a5", TxConsequences::new(1, SeqProxy::sequence(5))),
    );
    let mut success_views = QueueViews::new(
        std::collections::BTreeMap::from([("a", success_account)]),
        vec![tx::FeeQueueEntry::new(
            FeeQueueKey::new("a", SeqProxy::sequence(5)),
            QueueAdvanceCandidate {
                fee_level: 100,
                tx_id: basics::base_uint::Uint256::from_u64(5),
                seq_proxy: SeqProxy::sequence(5),
            },
        )],
    );

    let success = run_direct_apply_if_eligible(
        &mut success_views,
        true,
        SeqProxy::sequence(5),
        SeqProxy::sequence(5),
        100,
        100,
        &"a",
        || {
            invoked.set(invoked.get() + 1);
            ApplyResult::new(Ter::TES_SUCCESS, true, true)
        },
    );

    assert_eq!(invoked.get(), 1);
    assert_eq!(
        success,
        Some(DirectApplyAttemptResult {
            apply_result: ApplyResult::new(Ter::TES_SUCCESS, true, true),
            removed_replacement: Some(FeeQueueKey::new("a", SeqProxy::sequence(5))),
        })
    );
    assert!(success_views.fee_order.is_empty());
    assert!(success_views.accounts["a"].empty());

    let mut ineligible_views = QueueViews::<&str, &str>::default();
    let ineligible = run_direct_apply_if_eligible(
        &mut ineligible_views,
        false,
        SeqProxy::sequence(5),
        SeqProxy::sequence(5),
        100,
        100,
        &"a",
        || {
            invoked.set(invoked.get() + 1);
            ApplyResult::new(Ter::TES_SUCCESS, true, true)
        },
    );

    assert_eq!(ineligible, None);
    assert_eq!(invoked.get(), 1);
}

