#[test]
fn txq_apply_prerequisite_gate_matches_current_cpp_missing_account_and_ticket_rules() {
    let missing_account = evaluate_queue_apply_prerequisite(
        false,
        SeqProxy::sequence(8),
        SeqProxy::sequence(8),
        false,
    );
    let past_ticket =
        evaluate_queue_apply_prerequisite(true, SeqProxy::sequence(8), SeqProxy::ticket(7), false);
    let future_ticket =
        evaluate_queue_apply_prerequisite(true, SeqProxy::sequence(8), SeqProxy::ticket(9), false);
    let ready =
        evaluate_queue_apply_prerequisite(true, SeqProxy::sequence(8), SeqProxy::ticket(9), true);

    assert_eq!(missing_account, QueueApplyPrerequisite::MissingAccount);
    assert_eq!(missing_account.ter(), Some(Ter::TER_NO_ACCOUNT));
    assert_eq!(past_ticket, QueueApplyPrerequisite::MissingTicketPast);
    assert_eq!(past_ticket.ter(), Some(Ter::TEF_NO_TICKET));
    assert_eq!(future_ticket, QueueApplyPrerequisite::MissingTicketFuture);
    assert_eq!(future_ticket.ter(), Some(Ter::TER_PRE_TICKET));
    assert_eq!(ready, QueueApplyPrerequisite::Ready);
    assert_eq!(ready.ter(), None);
}

#[test]
fn txq_apply_entry_returns_direct_apply_result_before_later_queue_guards() {
    let queued_called = std::cell::Cell::new(false);
    let direct = DirectApplyExecution {
        transaction_id: "ABC123",
        attempt: DirectApplyAttemptResult {
            apply_result: ApplyResult::new(Ter::TEF_NO_TICKET, false, false),
            removed_replacement: None::<FeeQueueKey<&'static str>>,
        },
    };

    let stage = run_queue_apply_entry_stage(
        true,
        SeqProxy::sequence(8),
        SeqProxy::ticket(7),
        false,
        || Some(direct.clone()),
        || {
            queued_called.set(true);
            QueueApplyQueuedStage::<&'static str, &'static str, &'static str, &'static str>::MultiTxn(
                QueueApplyMultiTxnStage::RejectPath(Ter::TER_PRE_SEQ),
            )
        },
    );

    assert_eq!(stage, QueueApplyEntryStage::DirectApplied(direct));
    assert_eq!(
        stage.apply_result(),
        ApplyResult::new(Ter::TEF_NO_TICKET, false, false)
    );
    assert!(!queued_called.get());
}

