#[test]
fn txq_top_after_preflight_from_sources_caller_queued_stage_exposes_prepared_queue_boundary() {
    let rules = Rules::new(std::iter::empty());
    let account_id = String::from("acct");
    let tx_source = ParityObservedTxSource {
        account: &account_id,
        transaction_id: "ABC123",
        tx_id: Uint256::from_u64(9),
        tx_seq_proxy: SeqProxy::sequence(6),
    };
    let view_source = ParityObservedViewSource {
        rules: rules.clone(),
        account_lookup: QueueApplyObservedAccountLookup::Present {
            sequence: 5,
            balance_drops: 1_000,
        },
        ticket_lookup: QueueApplyObservedTicketLookup::Present,
        calculated_base_fee_drops: 10,
        fee_paid_drops: 20,
        default_base_fee_drops: 10,
        metrics_snapshot: QueueFeeMetricsSnapshot {
            txns_expected: 32,
            escalation_multiplier: tx::TXQ_BASE_LEVEL * 500,
        },
        open_ledger_tx_count: 0,
        open_ledger_seq: 100,
        reserve_drops: 200,
        base_fee_drops: 10,
    };
    let mut views = QueueViews::new(std::collections::BTreeMap::new(), vec![]);
    let order = OrderCandidates::new(Uint256::from_u64(0));
    let direct_called = std::cell::Cell::new(false);
    let queued_called = std::cell::Cell::new(false);
    let fee_context_inputs = QueueApplyFeeContextInputs {
        calculated_base_fee_drops: 10,
        fee_paid_drops: 20,
        default_base_fee_drops: 10,
        metrics_snapshot: QueueFeeMetricsSnapshot {
            txns_expected: 32,
            escalation_multiplier: tx::TXQ_BASE_LEVEL * 500,
        },
        open_ledger_tx_count: 0,
        flags: ApplyFlags::NONE,
    };
    let expected_fee_context = evaluate_queue_apply_fee_context(fee_context_inputs);
    let preflight_result = PreflightResult::new(
        "tx",
        None::<&str>,
        rules.clone(),
        TxConsequences::new(1, SeqProxy::sequence(6)),
        ApplyFlags::NONE,
        "journal",
        Ter::TES_SUCCESS,
    );

    let stage =
        run_queue_apply_after_preflight_with_caller_direct_apply_and_caller_queued_stage_from_sources(
            &mut views,
            &tx_source,
            &view_source,
            &preflight_result,
            QueueApplyAfterPreflightSourceInputs::new(
                QueueHoldPreflight::new(false, false, ApplyFlags::NONE, Some(250)),
                QueueApplyObservedQueue {
                    minimum_last_ledger_buffer: 2,
                    maximum_txn_per_account: 10,
                    retry_sequence_percent: 25,
                    queue_is_full: false,
                    can_be_held_result: Ter::TES_SUCCESS,
                    order: &order,
                },
            ),
            |_views, _prepared| {
                direct_called.set(true);
                unreachable!("sequence mismatch should skip direct apply")
            },
            |_views, queued| {
                queued_called.set(true);
                assert_eq!(queued.account_seq_proxy, SeqProxy::sequence(5));
                assert_eq!(queued.tx_seq_proxy, SeqProxy::sequence(6));
                assert_eq!(queued.queued.account, account_id);
                assert_eq!(queued.queued.last_valid, Some(250));
                assert_eq!(queued.fee_context, expected_fee_context);
                assert_eq!(queued.preflight_result, preflight_result);

                QueueApplyQueuedStage::MultiTxn(QueueApplyMultiTxnStage::RejectPath(
                    Ter::TER_PRE_SEQ,
                ))
            },
        );

    assert!(!direct_called.get());
    assert!(queued_called.get());
    assert_eq!(
        stage,
        QueueApplyPreflightStage::Entry(QueueApplyEntryStage::Queued(
            QueueApplyQueuedStage::MultiTxn(QueueApplyMultiTxnStage::RejectPath(Ter::TER_PRE_SEQ)),
        ))
    );
}

#[test]
fn txq_top_after_preflight_wrapper_routes_direct_apply_fallthrough() {
    let rules = Rules::new(std::iter::empty());
    let mut account = TxQAccount::new("acct");
    account.add(
        SeqProxy::sequence(5),
        MaybeTxCore::new(
            MaybeTx::new(
                Uint256::from_u64(5),
                90,
                "acct",
                Some(200),
                SeqProxy::sequence(5),
                ApplyFlags::NONE,
                PreflightResult::new(
                    "tx",
                    None::<&str>,
                    rules.clone(),
                    TxConsequences::with_category(
                        1,
                        SeqProxy::sequence(5),
                        TxConsequencesCategory::Blocker,
                    ),
                    ApplyFlags::NONE,
                    "journal",
                    Ter::TES_SUCCESS,
                ),
            ),
            TxConsequences::with_category(
                1,
                SeqProxy::sequence(5),
                TxConsequencesCategory::Blocker,
            ),
        ),
    );
    let mut views = QueueViews::new(
        std::collections::BTreeMap::from([("acct", account)]),
        vec![],
    );
    let order = OrderCandidates::new(Uint256::from_u64(0));

    let stage = run_queue_apply_after_preflight_with_queued_stage(
        &mut views,
        QueueApplyTopWithQueuedStageInputs::new(
            QueueApplyTopWithDirectApplyInputs::new(
                QueueApplyTopWithFeeContextInputs::new(
                    QueueApplyCallInputs::new(
                        &rules,
                        true,
                        SeqProxy::sequence(5),
                        SeqProxy::sequence(6),
                        true,
                    ),
                    QueueApplyFeeContextInputs {
                        calculated_base_fee_drops: 10,
                        fee_paid_drops: 1,
                        default_base_fee_drops: 10,
                        metrics_snapshot: QueueFeeMetricsSnapshot {
                            txns_expected: 32,
                            escalation_multiplier: tx::TXQ_BASE_LEVEL * 500,
                        },
                        open_ledger_tx_count: 0,
                        flags: ApplyFlags::NONE,
                    },
                ),
                "ABC123",
                &"acct",
            ),
            QueueApplyQueuedWithFeeContextInputs {
                account: "acct",
                preflight: QueueHoldPreflight::new(false, false, ApplyFlags::NONE, None),
                is_blocker: true,
                open_ledger_seq: 100,
                minimum_last_ledger_buffer: 2,
                maximum_txn_per_account: 10,
                retry_sequence_percent: 25,
                queue_is_full: false,
                balance_drops: 1_000,
                reserve_drops: 200,
                base_fee_drops: 10,
                can_be_held_result: Ter::TES_SUCCESS,
                open_ledger_tx_count: 4,
                tx_id: Uint256::from_u64(9),
                last_valid: Some(250),
                flags: ApplyFlags::NONE,
                order: &order,
            },
        ),
        &PreflightResult::new(
            "tx",
            None::<&str>,
            rules.clone(),
            TxConsequences::with_category(
                1,
                SeqProxy::sequence(6),
                TxConsequencesCategory::Blocker,
            ),
            ApplyFlags::NONE,
            "journal",
            Ter::TES_SUCCESS,
        ),
        |_| unreachable!("direct apply should fall through without tracing"),
        || ApplyResult::new(Ter::TES_SUCCESS, true, true),
        |_| true,
        |view_source| {
            assert!(!view_source.has_multi_txn());
            PreclaimResult::new(
                100,
                "tx",
                None::<&str>,
                ApplyFlags::NONE,
                "journal",
                Ter::TES_SUCCESS,
            )
        },
        || -> ApplyResult {
            unreachable!("queue-stage account rejection should happen before try-clear")
        },
        || unreachable!("queue-stage account rejection should happen before sandbox apply"),
    );

    assert_eq!(
        stage,
        QueueApplyPreflightStage::Entry(QueueApplyEntryStage::Queued(
            QueueApplyQueuedStage::Account(tx::QueueApplyAccountStage::RejectBlockerAdmission(
                BlockerQueueAdmission::RejectsNonReplacementOfLoneEntry,
            )),
        ))
    );
}

