fn txq_top_after_preflight_with_direct_apply_returns_it() {
    let prepare_called = std::cell::Cell::new(false);
    let preclaim_called = std::cell::Cell::new(false);
    let try_clear_called = std::cell::Cell::new(false);
    let sandbox_called = std::cell::Cell::new(false);
    let traces = std::cell::RefCell::new(Vec::new());

    let rules = Rules::new(std::iter::empty());
    let mut views = QueueViews::<
        &'static str,
        MaybeTx<&'static str, &'static str, &'static str, &'static str>,
    >::new(std::collections::BTreeMap::new(), vec![]);
    let order = OrderCandidates::new(Uint256::from_u64(0));

    let stage = run_queue_apply_after_preflight_with_direct_apply_and_queued_stage(
        &mut views,
        QueueApplyTopWithQueuedStageInputs::new(
            QueueApplyTopWithDirectApplyInputs::new(
                QueueApplyTopWithFeeContextInputs::new(
                    QueueApplyCallInputs::new(
                        &rules,
                        true,
                        SeqProxy::sequence(8),
                        SeqProxy::sequence(8),
                        true,
                    ),
                    QueueApplyFeeContextInputs {
                        calculated_base_fee_drops: 10,
                        fee_paid_drops: 20,
                        default_base_fee_drops: 10,
                        metrics_snapshot: QueueFeeMetricsSnapshot {
                            txns_expected: 32,
                            escalation_multiplier: tx::TXQ_BASE_LEVEL * 500,
                        },
                        open_ledger_tx_count: 0,
                        flags: ApplyFlags::NONE,
                    },
                ),
                "ABC123",
                &"acct",
            ),
            QueueApplyQueuedWithFeeContextInputs {
                account: "acct",
                preflight: QueueHoldPreflight::new(false, false, ApplyFlags::NONE, None),
                is_blocker: false,
                open_ledger_seq: 100,
                minimum_last_ledger_buffer: 2,
                maximum_txn_per_account: 10,
                retry_sequence_percent: 25,
                queue_is_full: false,
                balance_drops: 1_000,
                reserve_drops: 200,
                base_fee_drops: 10,
                can_be_held_result: Ter::TES_SUCCESS,
                open_ledger_tx_count: 4,
                tx_id: Uint256::from_u64(9),
                last_valid: Some(250),
                flags: ApplyFlags::NONE,
                order: &order,
            },
        ),
        &PreflightResult::new(
            "tx",
            None::<&str>,
            rules.clone(),
            TxConsequences::new(1, SeqProxy::sequence(8)),
            ApplyFlags::NONE,
            "journal",
            Ter::TES_SUCCESS,
        ),
        |line| traces.borrow_mut().push(line.to_owned()),
        || ApplyResult::new(Ter::TES_SUCCESS, true, true),
        |_| {
            prepare_called.set(true);
            true
        },
        |_| {
            preclaim_called.set(true);
            PreclaimResult::new(
                100,
                "tx",
                None::<&str>,
                ApplyFlags::NONE,
                "journal",
                Ter::TES_SUCCESS,
            )
        },
        || {
            try_clear_called.set(true);
            ApplyResult::new(Ter::TES_SUCCESS, true, true)
        },
        || sandbox_called.set(true),
    );

    assert!(matches!(
        stage,
        QueueApplyPreflightStage::Entry(QueueApplyEntryStage::DirectApplied(_))
    ));
    assert!(!prepare_called.get());
    assert!(!preclaim_called.get());
    assert!(!try_clear_called.get());
    assert!(!sandbox_called.get());
    assert_eq!(
        traces.into_inner(),
        vec![
            "Applying transaction ABC123 to open ledger.".to_owned(),
            "New transaction ABC123 applied successfully with tesSUCCESS".to_owned(),
        ]
    );
}

#[test]
fn txq_apply_top_with_queued_stage_routes_direct_apply_fallthrough() {
    let rules = Rules::new(std::iter::empty());
    let mut account = TxQAccount::new("acct");
    account.add(
        SeqProxy::sequence(5),
        MaybeTxCore::new(
            MaybeTx::new(
                Uint256::from_u64(5),
                90,
                "acct",
                Some(200),
                SeqProxy::sequence(5),
                ApplyFlags::NONE,
                PreflightResult::new(
                    "tx",
                    None::<&str>,
                    rules.clone(),
                    TxConsequences::with_category(
                        1,
                        SeqProxy::sequence(5),
                        TxConsequencesCategory::Blocker,
                    ),
                    ApplyFlags::NONE,
                    "journal",
                    Ter::TES_SUCCESS,
                ),
            ),
            TxConsequences::with_category(
                1,
                SeqProxy::sequence(5),
                TxConsequencesCategory::Blocker,
            ),
        ),
    );
    let mut views = QueueViews::new(
        std::collections::BTreeMap::from([("acct", account)]),
        vec![],
    );
    let order = OrderCandidates::new(Uint256::from_u64(0));

    let stage = run_queue_apply_top_with_queued_stage(
        &mut views,
        QueueApplyTopWithQueuedStageInputs::new(
            QueueApplyTopWithDirectApplyInputs::new(
                QueueApplyTopWithFeeContextInputs::new(
                    QueueApplyCallInputs::new(
                        &rules,
                        true,
                        SeqProxy::sequence(5),
                        SeqProxy::sequence(6),
                        true,
                    ),
                    QueueApplyFeeContextInputs {
                        calculated_base_fee_drops: 10,
                        fee_paid_drops: 1,
                        default_base_fee_drops: 10,
                        metrics_snapshot: QueueFeeMetricsSnapshot {
                            txns_expected: 32,
                            escalation_multiplier: tx::TXQ_BASE_LEVEL * 500,
                        },
                        open_ledger_tx_count: 0,
                        flags: ApplyFlags::NONE,
                    },
                ),
                "ABC123",
                &"acct",
            ),
            QueueApplyQueuedWithFeeContextInputs {
                account: "acct",
                preflight: QueueHoldPreflight::new(false, false, ApplyFlags::NONE, None),
                is_blocker: true,
                open_ledger_seq: 100,
                minimum_last_ledger_buffer: 2,
                maximum_txn_per_account: 10,
                retry_sequence_percent: 25,
                queue_is_full: false,
                balance_drops: 1_000,
                reserve_drops: 200,
                base_fee_drops: 10,
                can_be_held_result: Ter::TES_SUCCESS,
                open_ledger_tx_count: 4,
                tx_id: Uint256::from_u64(9),
                last_valid: Some(250),
                flags: ApplyFlags::NONE,
                order: &order,
            },
        ),
        || {
            PreflightResult::new(
                "tx",
                None::<&str>,
                rules.clone(),
                TxConsequences::with_category(
                    1,
                    SeqProxy::sequence(6),
                    TxConsequencesCategory::Blocker,
                ),
                ApplyFlags::NONE,
                "journal",
                Ter::TES_SUCCESS,
            )
        },
        |_| unreachable!("direct-apply trace should not run for an ineligible direct apply"),
        || ApplyResult::new(Ter::TES_SUCCESS, true, true),
        |_| true,
        |view_source| {
            assert!(!view_source.has_multi_txn());
            PreclaimResult::new(
                100,
                "tx",
                None::<&str>,
                ApplyFlags::NONE,
                "journal",
                Ter::TES_SUCCESS,
            )
        },
        || -> ApplyResult { unreachable!("account rejection should happen before try-clear") },
        || unreachable!("account rejection should happen before sandbox apply"),
    );

    assert_eq!(
        stage,
        QueueApplyPreflightStage::Entry(QueueApplyEntryStage::Queued(
            QueueApplyQueuedStage::Account(QueueApplyAccountStage::RejectBlockerAdmission(
                BlockerQueueAdmission::RejectsNonReplacementOfLoneEntry
            ))
        ))
    );
}

#[test]
fn txq_blocker_queue_admission_matches_current_cpp_lone_replacement_rule() {
    let crowded = evaluate_blocker_queue_admission(true, 2, SeqProxy::sequence(5), None);
    let wrong_replacement = evaluate_blocker_queue_admission(
        true,
        1,
        SeqProxy::sequence(5),
        Some(SeqProxy::sequence(7)),
    );
    let good_replacement = evaluate_blocker_queue_admission(
        true,
        1,
        SeqProxy::sequence(5),
        Some(SeqProxy::sequence(5)),
    );
    let normal = evaluate_blocker_queue_admission(false, 3, SeqProxy::sequence(5), None);

    assert_eq!(crowded, BlockerQueueAdmission::RejectsCoResidentQueue);
    assert_eq!(crowded.ter(), Some(Ter::TEL_CAN_NOT_QUEUE_BLOCKS));
    assert_eq!(
        wrong_replacement,
        BlockerQueueAdmission::RejectsNonReplacementOfLoneEntry
    );
    assert_eq!(wrong_replacement.ter(), Some(Ter::TEL_CAN_NOT_QUEUE_BLOCKS));
    assert_eq!(good_replacement, BlockerQueueAdmission::Allowed);
    assert_eq!(normal, BlockerQueueAdmission::Allowed);
}

#[test]
fn txq_account_queue_window_matches_current_cpp_lower_bound_and_replace_split() {
    let mut account = TxQAccount::new("acct");
    account.add(
        SeqProxy::sequence(5),
        MaybeTxCore::new("s5", TxConsequences::new(1, SeqProxy::sequence(5))),
    );
    account.add(
        SeqProxy::sequence(7),
        MaybeTxCore::new("s7", TxConsequences::new(1, SeqProxy::sequence(7))),
    );
    account.add(
        SeqProxy::ticket(3),
        MaybeTxCore::new("t3", TxConsequences::new(1, SeqProxy::ticket(3))),
    );

    let active =
        inspect_account_queue_window(Some(&account), SeqProxy::sequence(6), SeqProxy::sequence(7));
    assert_eq!(
        active,
        tx::AccountQueueWindow {
            account_is_in_queue: true,
            first_relevant_seq_proxy: Some(SeqProxy::sequence(7)),
            relevant_tx_count: 2,
            replaces_existing: true,
            front_is_blocker: false,
        }
    );

    let mut slipped_only = TxQAccount::new("acct");
    slipped_only.add(
        SeqProxy::sequence(5),
        MaybeTxCore::new("s5", TxConsequences::new(1, SeqProxy::sequence(5))),
    );
    slipped_only.add(
        SeqProxy::sequence(7),
        MaybeTxCore::new("s7", TxConsequences::new(1, SeqProxy::sequence(7))),
    );
    let ignored = inspect_account_queue_window(
        Some(&slipped_only),
        SeqProxy::sequence(8),
        SeqProxy::sequence(5),
    );
    assert_eq!(
        ignored,
        tx::AccountQueueWindow {
            account_is_in_queue: true,
            first_relevant_seq_proxy: None,
            relevant_tx_count: 0,
            replaces_existing: true,
            front_is_blocker: false,
        }
    );
}

#[test]
fn txq_apply_account_stage_carries_locked_queue_context() {
    let mut queued = MaybeTx::new(
        Uint256::from_u64(7),
        100,
        "acct",
        Some(200),
        SeqProxy::sequence(7),
        ApplyFlags::NONE,
        PreflightResult::new(
            "tx",
            None::<&str>,
            Rules::new(std::iter::empty()),
            TxConsequences::new(1, SeqProxy::sequence(7)),
            ApplyFlags::NONE,
            "journal",
            Ter::TES_SUCCESS,
        ),
    );
    queued.retries_remaining = 8;

    let mut account = TxQAccount::new("acct");
    account.add(
        SeqProxy::sequence(7),
        MaybeTxCore::new(queued, TxConsequences::new(1, SeqProxy::sequence(7))),
    );
    account.add(
        SeqProxy::ticket(9),
        MaybeTxCore::new(
            MaybeTx::new(
                Uint256::from_u64(9),
                80,
                "acct",
                Some(200),
                SeqProxy::ticket(9),
                ApplyFlags::NONE,
                PreflightResult::new(
                    "tx",
                    None::<&str>,
                    Rules::new(std::iter::empty()),
                    TxConsequences::new(1, SeqProxy::ticket(9)),
                    ApplyFlags::NONE,
                    "journal",
                    Ter::TES_SUCCESS,
                ),
            ),
            TxConsequences::new(1, SeqProxy::ticket(9)),
        ),
    );
    let views = QueueViews::new(
        std::collections::BTreeMap::from([("acct", account)]),
        vec![],
    );

    let stage = run_queue_apply_account_stage(
        &views,
        &"acct",
        SeqProxy::sequence(7),
        SeqProxy::sequence(7),
        false,
        126,
        25,
    );

    assert_eq!(
        stage,
        QueueApplyAccountStage::Ready(QueueApplyAccountContext {
            window: tx::AccountQueueWindow {
                account_is_in_queue: true,
                first_relevant_seq_proxy: Some(SeqProxy::sequence(7)),
                relevant_tx_count: 2,
                replaces_existing: true,
                front_is_blocker: false,
            },
            first_relevant_retries_remaining: Some(8),
            replacement_decision: Some(ReplacementFeeDecision::ReplaceAllowed {
                required_fee_level: 125,
            }),
            replaced: Some(FeeQueueKey::new("acct", SeqProxy::sequence(7))),
        })
    );
}

