#[test]
fn txq_existing_blocker_gate_matches_current_cpp_blocked_rule() {
    let mut account = TxQAccount::new("acct");
    account.add(
        SeqProxy::sequence(5),
        MaybeTxCore::new(
            "blocker",
            TxConsequences::with_category(
                1,
                SeqProxy::sequence(5),
                TxConsequencesCategory::Blocker,
            ),
        ),
    );

    let window =
        inspect_account_queue_window(Some(&account), SeqProxy::sequence(5), SeqProxy::sequence(7));
    let blocked = evaluate_queued_blocker_admission(window, SeqProxy::sequence(7));
    let replacement = evaluate_queued_blocker_admission(window, SeqProxy::sequence(5));

    assert_eq!(blocked, QueuedBlockerAdmission::BlockedByQueuedBlocker);
    assert_eq!(blocked.ter(), Some(Ter::TEL_CAN_NOT_QUEUE_BLOCKED));
    assert_eq!(replacement, QueuedBlockerAdmission::Allowed);
}

#[test]
fn txq_replacement_fee_gate_matches_current_cpp_retry_sequence_rule() {
    assert_eq!(increase_replacement_fee_level(100, 25), 125);
    assert_eq!(increase_replacement_fee_level(101, 25), 126);

    let equal = evaluate_replacement_fee(125, 100, 25);
    let higher = evaluate_replacement_fee(126, 100, 25);
    let overflow = evaluate_replacement_fee(u64::MAX, u64::MAX, 100);

    assert_eq!(
        equal,
        ReplacementFeeDecision::InsufficientFee {
            required_fee_level: 125
        }
    );
    assert_eq!(equal.ter(), Some(Ter::TEL_CAN_NOT_QUEUE_FEE));
    assert_eq!(
        higher,
        ReplacementFeeDecision::ReplaceAllowed {
            required_fee_level: 125
        }
    );
    assert_eq!(higher.ter(), None);
    assert_eq!(
        overflow,
        ReplacementFeeDecision::InsufficientFee {
            required_fee_level: u64::MAX
        }
    );
}

#[test]
fn txq_apply_path_matches_current_cpp_account_split_and_multitxn_rule() {
    assert_eq!(
        evaluate_queue_apply_path(0, SeqProxy::sequence(4), SeqProxy::sequence(5), false),
        Err(Ter::TEF_PAST_SEQ)
    );
    assert_eq!(
        evaluate_queue_apply_path(0, SeqProxy::sequence(6), SeqProxy::sequence(5), false),
        Err(Ter::TER_PRE_SEQ)
    );
    assert_eq!(
        evaluate_queue_apply_path(0, SeqProxy::ticket(9), SeqProxy::sequence(5), false),
        Ok(QueueApplyPath::OpenLedger)
    );
    assert_eq!(
        evaluate_queue_apply_path(1, SeqProxy::sequence(4), SeqProxy::sequence(5), false),
        Err(Ter::TEF_PAST_SEQ)
    );
    assert_eq!(
        evaluate_queue_apply_path(1, SeqProxy::sequence(5), SeqProxy::sequence(5), true),
        Ok(QueueApplyPath::QueuedAccount {
            requires_multi_txn: false
        })
    );
    assert_eq!(
        evaluate_queue_apply_path(1, SeqProxy::sequence(5), SeqProxy::sequence(5), false),
        Ok(QueueApplyPath::QueuedAccount {
            requires_multi_txn: true
        })
    );
    assert_eq!(
        evaluate_queue_apply_path(2, SeqProxy::sequence(5), SeqProxy::sequence(5), true),
        Ok(QueueApplyPath::QueuedAccount {
            requires_multi_txn: true
        })
    );
}

#[test]
fn txq_apply_multitxn_admission_matches_current_cpp_pre_multitxn_order() {
    let mut replacement_account = TxQAccount::new("acct");
    replacement_account.add(
        SeqProxy::sequence(5),
        MaybeTxCore::new(
            "s5",
            TxConsequences::with_sequences_consumed(1, SeqProxy::sequence(5), 1),
        ),
    );
    replacement_account.add(
        SeqProxy::sequence(6),
        MaybeTxCore::new(
            "s6",
            TxConsequences::with_sequences_consumed(1, SeqProxy::sequence(6), 1),
        ),
    );

    assert_eq!(
        evaluate_queue_apply_multitxn_admission(
            QueueApplyPath::OpenLedger,
            QueueHoldPreflight::new(true, false, ApplyFlags::FAIL_HARD, Some(1)),
            100,
            2,
            &replacement_account,
            2,
            SeqProxy::sequence(9),
            SeqProxy::sequence(5),
            false,
        ),
        Ok(QueueApplyPath::OpenLedger)
    );
    assert_eq!(
        evaluate_queue_apply_multitxn_admission(
            QueueApplyPath::QueuedAccount {
                requires_multi_txn: false
            },
            QueueHoldPreflight::new(true, false, ApplyFlags::FAIL_HARD, Some(1)),
            100,
            2,
            &replacement_account,
            2,
            SeqProxy::sequence(6),
            SeqProxy::sequence(5),
            true,
        ),
        Ok(QueueApplyPath::QueuedAccount {
            requires_multi_txn: false
        })
    );
    assert_eq!(
        evaluate_queue_apply_multitxn_admission(
            QueueApplyPath::QueuedAccount {
                requires_multi_txn: true
            },
            QueueHoldPreflight::new(false, false, ApplyFlags::NONE, None),
            100,
            2,
            &replacement_account,
            2,
            SeqProxy::sequence(6),
            SeqProxy::sequence(5),
            true,
        ),
        Ok(QueueApplyPath::QueuedAccount {
            requires_multi_txn: true
        })
    );

    let mut gap_fill_account = TxQAccount::new("acct");
    gap_fill_account.add(
        SeqProxy::sequence(5),
        MaybeTxCore::new(
            "s5",
            TxConsequences::with_sequences_consumed(1, SeqProxy::sequence(5), 1),
        ),
    );
    gap_fill_account.add(
        SeqProxy::sequence(7),
        MaybeTxCore::new(
            "s7",
            TxConsequences::with_sequences_consumed(1, SeqProxy::sequence(7), 1),
        ),
    );

    assert_eq!(
        evaluate_queue_apply_multitxn_admission(
            QueueApplyPath::QueuedAccount {
                requires_multi_txn: true
            },
            QueueHoldPreflight::new(true, false, ApplyFlags::NONE, None),
            100,
            2,
            &gap_fill_account,
            2,
            SeqProxy::sequence(8),
            SeqProxy::sequence(5),
            false,
        ),
        Err(Ter::TEL_CAN_NOT_QUEUE)
    );
    assert_eq!(
        evaluate_queue_apply_multitxn_admission(
            QueueApplyPath::QueuedAccount {
                requires_multi_txn: true
            },
            QueueHoldPreflight::new(false, false, ApplyFlags::NONE, None),
            100,
            2,
            &gap_fill_account,
            3,
            SeqProxy::sequence(8),
            SeqProxy::sequence(5),
            false,
        ),
        Err(Ter::TEL_CAN_NOT_QUEUE)
    );
    assert_eq!(
        evaluate_queue_apply_multitxn_admission(
            QueueApplyPath::QueuedAccount {
                requires_multi_txn: true
            },
            QueueHoldPreflight::new(false, false, ApplyFlags::NONE, None),
            100,
            2,
            &gap_fill_account,
            2,
            SeqProxy::sequence(6),
            SeqProxy::sequence(5),
            false,
        ),
        Ok(QueueApplyPath::QueuedAccount {
            requires_multi_txn: true
        })
    );
}

#[test]
fn txq_apply_balance_gate_matches_current_cpp_tail_and_reserve_rules() {
    let mut account = TxQAccount::new("acct");
    account.add(
        SeqProxy::sequence(5),
        MaybeTxCore::new(
            "s5",
            TxConsequences::with_potential_spend(10, SeqProxy::sequence(5), 100),
        ),
    );
    account.add(
        SeqProxy::sequence(6),
        MaybeTxCore::new(
            "s6",
            TxConsequences::with_potential_spend(20, SeqProxy::sequence(6), 200),
        ),
    );
    account.add(
        SeqProxy::sequence(8),
        MaybeTxCore::new(
            "s8",
            TxConsequences::with_potential_spend(30, SeqProxy::sequence(8), 300),
        ),
    );

    assert_eq!(
        evaluate_queue_apply_balance(
            &account,
            SeqProxy::sequence(5),
            SeqProxy::sequence(6),
            TxConsequences::with_potential_spend(50, SeqProxy::sequence(6), 500),
            1_000,
            500,
            10,
        ),
        QueueApplyBalanceDecision::Allowed(tx::QueueApplyBalanceTotals {
            total_fee_drops: 90,
            potential_spend_drops: 900,
        })
    );

    let balance_fail = evaluate_queue_apply_balance(
        &account,
        SeqProxy::sequence(5),
        SeqProxy::sequence(9),
        TxConsequences::with_potential_spend(1, SeqProxy::sequence(9), 1),
        60,
        1_000,
        10,
    );
    assert_eq!(
        balance_fail,
        QueueApplyBalanceDecision::TotalFeesInFlightTooHigh(tx::QueueApplyBalanceTotals {
            total_fee_drops: 60,
            potential_spend_drops: 600,
        })
    );
    assert_eq!(balance_fail.ter(), Some(Ter::TEL_CAN_NOT_QUEUE_BALANCE));

    let reserve_fail = evaluate_queue_apply_balance(
        &account,
        SeqProxy::sequence(5),
        SeqProxy::sequence(9),
        TxConsequences::with_potential_spend(1, SeqProxy::sequence(9), 1),
        1_000,
        60,
        5,
    );
    assert_eq!(
        reserve_fail,
        QueueApplyBalanceDecision::TotalFeesInFlightTooHigh(tx::QueueApplyBalanceTotals {
            total_fee_drops: 60,
            potential_spend_drops: 600,
        })
    );
}

