#[test]
fn queue_apply_full_queue_matches_current_cpp_account_average_eviction_rule() {
    let mut alice = TxQAccount::new("alice");
    alice.add(
        SeqProxy::sequence(5),
        MaybeTxCore::new(10_u64, TxConsequences::new(1, SeqProxy::sequence(5))),
    );

    let mut bob = TxQAccount::new("bob");
    bob.add(
        SeqProxy::sequence(8),
        MaybeTxCore::new(40_u64, TxConsequences::new(1, SeqProxy::sequence(8))),
    );
    bob.add(
        SeqProxy::sequence(9),
        MaybeTxCore::new(80_u64, TxConsequences::new(1, SeqProxy::sequence(9))),
    );

    let fee_order = vec![
        FeeQueueEntry::new(
            FeeQueueKey::new("alice", SeqProxy::sequence(5)),
            QueueAdvanceCandidate {
                fee_level: 100,
                tx_id: basics::base_uint::Uint256::from_u64(5),
                seq_proxy: SeqProxy::sequence(5),
            },
        ),
        FeeQueueEntry::new(
            FeeQueueKey::new("bob", SeqProxy::sequence(8)),
            QueueAdvanceCandidate {
                fee_level: 80,
                tx_id: basics::base_uint::Uint256::from_u64(8),
                seq_proxy: SeqProxy::sequence(8),
            },
        ),
        FeeQueueEntry::new(
            FeeQueueKey::new("bob", SeqProxy::sequence(9)),
            QueueAdvanceCandidate {
                fee_level: 40,
                tx_id: basics::base_uint::Uint256::from_u64(9),
                seq_proxy: SeqProxy::sequence(9),
            },
        ),
    ];

    let accounts = std::collections::BTreeMap::from([("alice", alice), ("bob", bob)]);

    assert_eq!(
        evaluate_queue_apply_full_queue(
            false,
            true,
            &"alice",
            70,
            &fee_order,
            &accounts,
            |queued| { queued.payload }
        ),
        QueueApplyFullQueueDecision::EvictCheapest {
            dropped: FeeQueueKey::new("bob", SeqProxy::sequence(9)),
            end_effective_fee_level: 60,
        }
    );
    assert_eq!(
        evaluate_queue_apply_full_queue(
            false,
            true,
            &"alice",
            60,
            &fee_order,
            &accounts,
            |queued| { queued.payload }
        ),
        QueueApplyFullQueueDecision::RejectFullLowerFee {
            end_effective_fee_level: 60,
        }
    );
}

