#[test]
fn txq_apply_try_clear_stage_only_applies_sandbox_for_applied_result() {
    let bypass = run_queue_apply_try_clear_stage(
        QueueApplyTryClearGate::Bypass,
        || ApplyResult::new(Ter::TES_SUCCESS, true, false),
        || panic!("bypass must not apply sandbox"),
    );
    assert_eq!(bypass, QueueApplyTryClearStage::Bypass);

    let continue_after_attempt = run_queue_apply_try_clear_stage(
        QueueApplyTryClearGate::AttemptClearAhead,
        || ApplyResult::new(Ter::TER_RETRY, false, false),
        || panic!("failed clear-ahead attempt must not apply sandbox"),
    );
    assert_eq!(
        continue_after_attempt,
        QueueApplyTryClearStage::ContinueAfterAttempt
    );

    let sandbox_applied = std::cell::Cell::new(false);
    let applied = run_queue_apply_try_clear_stage(
        QueueApplyTryClearGate::AttemptClearAhead,
        || ApplyResult::new(Ter::TES_SUCCESS, true, false),
        || sandbox_applied.set(true),
    );
    assert_eq!(
        applied,
        QueueApplyTryClearStage::ApplySandboxAndReturn(ApplyResult::new(
            Ter::TES_SUCCESS,
            true,
            false,
        ))
    );
    assert!(sandbox_applied.get());
}

#[test]
fn txq_apply_queue_stage_runs_hold_full_queue_and_enqueue_in() {
    let mut account_a = TxQAccount::new("a");
    account_a.add(
        SeqProxy::sequence(5),
        MaybeTxCore::new(
            MaybeTx::new(
                Uint256::from_u64(5),
                90,
                "a",
                Some(200),
                SeqProxy::sequence(5),
                ApplyFlags::NONE,
                PreflightResult::new(
                    "tx",
                    None::<&str>,
                    Rules::new(std::iter::empty()),
                    TxConsequences::new(1, SeqProxy::sequence(5)),
                    ApplyFlags::NONE,
                    "journal",
                    Ter::TES_SUCCESS,
                ),
            ),
            TxConsequences::new(1, SeqProxy::sequence(5)),
        ),
    );

    let mut account_b = TxQAccount::new("b");
    account_b.add(
        SeqProxy::sequence(8),
        MaybeTxCore::new(
            MaybeTx::new(
                Uint256::from_u64(8),
                50,
                "b",
                Some(200),
                SeqProxy::sequence(8),
                ApplyFlags::NONE,
                PreflightResult::new(
                    "tx",
                    None::<&str>,
                    Rules::new(std::iter::empty()),
                    TxConsequences::new(1, SeqProxy::sequence(8)),
                    ApplyFlags::NONE,
                    "journal",
                    Ter::TES_SUCCESS,
                ),
            ),
            TxConsequences::new(1, SeqProxy::sequence(8)),
        ),
    );

    let mut views = QueueViews::new(
        std::collections::BTreeMap::from([("a", account_a), ("b", account_b)]),
        vec![
            FeeQueueEntry::new(
                FeeQueueKey::new("a", SeqProxy::sequence(5)),
                QueueAdvanceCandidate {
                    fee_level: 90,
                    tx_id: Uint256::from_u64(5),
                    seq_proxy: SeqProxy::sequence(5),
                },
            ),
            FeeQueueEntry::new(
                FeeQueueKey::new("b", SeqProxy::sequence(8)),
                QueueAdvanceCandidate {
                    fee_level: 50,
                    tx_id: Uint256::from_u64(8),
                    seq_proxy: SeqProxy::sequence(8),
                },
            ),
        ],
    );

    let stage = run_queue_apply_queue_stage(
        &mut views,
        QueueApplyHoldFallback::AlreadyVerifiedByMultiTxn,
        QueueApplyFullQueueDecision::EvictCheapest {
            dropped: FeeQueueKey::new("b", SeqProxy::sequence(8)),
            end_effective_fee_level: 50,
        },
        None,
        "c",
        Uint256::from_u64(9),
        Some(250),
        SeqProxy::sequence(6),
        110,
        ApplyFlags::FAIL_HARD | ApplyFlags::RETRY,
        PreflightResult::new(
            "tx",
            None::<&str>,
            Rules::new(std::iter::empty()),
            TxConsequences::new(1, SeqProxy::sequence(6)),
            ApplyFlags::FAIL_HARD | ApplyFlags::RETRY,
            "journal",
            Ter::TES_SUCCESS,
        ),
        &OrderCandidates::new(Uint256::from_u64(0)),
    );

    assert_eq!(stage.ter(), Ter::TER_QUEUED);
    assert_eq!(
        stage.apply_result(),
        ApplyResult::new(Ter::TER_QUEUED, false, false)
    );
    assert!(matches!(stage, QueueApplyQueueStage::Queued(_)));
    assert!(views.accounts.contains_key("b"));
    assert!(views.accounts["b"].transactions.is_empty());
    assert!(views.accounts.contains_key("c"));
}

#[test]
fn txq_apply_queue_stage_caller_enqueue_boundary_exposes_prepared_enqueue() {
    let mut account_a = TxQAccount::new("a");
    account_a.add(
        SeqProxy::sequence(5),
        MaybeTxCore::new(
            MaybeTx::new(
                Uint256::from_u64(5),
                90,
                "a",
                Some(200),
                SeqProxy::sequence(5),
                ApplyFlags::NONE,
                PreflightResult::new(
                    "existing",
                    None::<&str>,
                    Rules::new(std::iter::empty()),
                    TxConsequences::new(1, SeqProxy::sequence(5)),
                    ApplyFlags::NONE,
                    "journal",
                    Ter::TES_SUCCESS,
                ),
            ),
            TxConsequences::new(1, SeqProxy::sequence(5)),
        ),
    );

    let mut views = QueueViews::new(
        std::collections::BTreeMap::from([("a", account_a)]),
        vec![FeeQueueEntry::new(
            FeeQueueKey::new("a", SeqProxy::sequence(5)),
            QueueAdvanceCandidate {
                fee_level: 90,
                tx_id: Uint256::from_u64(5),
                seq_proxy: SeqProxy::sequence(5),
            },
        )],
    );
    let preflight = PreflightResult::new(
        "tx",
        None::<&str>,
        Rules::new(std::iter::empty()),
        TxConsequences::new(1, SeqProxy::sequence(6)),
        ApplyFlags::RETRY,
        "journal",
        Ter::TES_SUCCESS,
    );
    let order = OrderCandidates::new(Uint256::from_u64(0));

    let stage = run_queue_apply_queue_stage_with_caller_enqueue(
        &mut views,
        QueueApplyHoldFallback::AlreadyVerifiedByMultiTxn,
        QueueApplyFullQueueDecision::Bypass,
        Some(FeeQueueKey::new("a", SeqProxy::sequence(5))),
        "a",
        Uint256::from_u64(9),
        Some(250),
        SeqProxy::sequence(6),
        110,
        ApplyFlags::RETRY,
        preflight.clone(),
        &order,
        |views, prepared| {
            apply_queue_apply_full_queue_decision(views, prepared.full_queue_decision)
        },
        |_views, prepared| {
            assert_eq!(
                prepared.full_queue_decision,
                QueueApplyFullQueueDecision::Bypass
            );
            assert_eq!(
                prepared.replaced,
                Some(FeeQueueKey::new("a", SeqProxy::sequence(5)))
            );
            assert_eq!(prepared.account, "a");
            assert_eq!(prepared.tx_id, Uint256::from_u64(9));
            assert_eq!(prepared.last_valid, Some(250));
            assert_eq!(prepared.seq_proxy, SeqProxy::sequence(6));
            assert_eq!(prepared.fee_level, 110);
            assert_eq!(prepared.flags, ApplyFlags::RETRY);
            assert_eq!(prepared.pf_result, preflight);
            assert!(std::ptr::eq(prepared.order, &order));

            QueueApplyEnqueueResult {
                queued: FeeQueueKey::new("a", SeqProxy::sequence(6)),
                removed_replacement: Some(FeeQueueKey::new("a", SeqProxy::sequence(5))),
                account_created: false,
                stored_flags: ApplyFlags::NONE,
            }
        },
    );

    assert_eq!(stage.ter(), Ter::TER_QUEUED);
    assert_eq!(
        stage.apply_result(),
        ApplyResult::new(Ter::TER_QUEUED, false, false)
    );
    assert!(matches!(stage, QueueApplyQueueStage::Queued(_)));
}

