#[test]
fn txq_apply_flow_stage_returns_preclaim_rejection_before_try_clear() {
    let ran_try_clear = std::cell::Cell::new(false);
    let sandbox_applied = std::cell::Cell::new(false);
    let mut views = QueueViews::new(std::collections::BTreeMap::new(), vec![]);

    let stage = run_queue_apply_flow_stage(
        &mut views,
        QueueApplyPreclaimViewSource::CurrentView,
        SeqProxy::sequence(6),
        None,
        110,
        100,
        105,
        4,
        QueueApplyHoldFallback::HoldAllowed,
        QueueApplyFullQueueDecision::Bypass,
        None,
        "acct",
        Uint256::from_u64(9),
        Some(250),
        ApplyFlags::NONE,
        PreflightResult::new(
            "tx",
            None::<&str>,
            Rules::new(std::iter::empty()),
            TxConsequences::new(1, SeqProxy::sequence(6)),
            ApplyFlags::NONE,
            "journal",
            Ter::TES_SUCCESS,
        ),
        &OrderCandidates::new(Uint256::from_u64(0)),
        |_| {
            PreflightResult::new(
                "tx",
                None::<&str>,
                Rules::new(std::iter::empty()),
                TxConsequences::new(1, SeqProxy::sequence(6)),
                ApplyFlags::NONE,
                "journal",
                Ter::TES_SUCCESS,
            )
            .to_preclaim(9, Ter::TER_RETRY)
        },
        || {
            ran_try_clear.set(true);
            ApplyResult::new(Ter::TES_SUCCESS, true, false)
        },
        || sandbox_applied.set(true),
    );

    assert_eq!(
        stage,
        QueueApplyFlowStage::RejectPreclaim(ApplyResult::new(Ter::TER_RETRY, false, false,))
    );
    assert_eq!(
        stage.apply_result(),
        ApplyResult::new(Ter::TER_RETRY, false, false)
    );
    assert!(!ran_try_clear.get());
    assert!(!sandbox_applied.get());
    assert!(views.accounts.is_empty());
}

#[test]
fn txq_apply_flow_stage_returns_applied_try_clear_before_queue() {
    let sandbox_applied = std::cell::Cell::new(false);
    let mut views = QueueViews::new(std::collections::BTreeMap::new(), vec![]);

    let stage = run_queue_apply_flow_stage(
        &mut views,
        QueueApplyPreclaimViewSource::MultiTxnOpenView,
        SeqProxy::sequence(6),
        Some(MAYBE_TX_RETRIES_ALLOWED),
        110,
        100,
        105,
        4,
        QueueApplyHoldFallback::AlreadyVerifiedByMultiTxn,
        QueueApplyFullQueueDecision::Bypass,
        None,
        "acct",
        Uint256::from_u64(9),
        Some(250),
        ApplyFlags::NONE,
        PreflightResult::new(
            "tx",
            None::<&str>,
            Rules::new(std::iter::empty()),
            TxConsequences::new(1, SeqProxy::sequence(6)),
            ApplyFlags::NONE,
            "journal",
            Ter::TES_SUCCESS,
        ),
        &OrderCandidates::new(Uint256::from_u64(0)),
        |source| {
            assert_eq!(source, QueueApplyPreclaimViewSource::MultiTxnOpenView);
            PreflightResult::new(
                "tx",
                None::<&str>,
                Rules::new(std::iter::empty()),
                TxConsequences::new(1, SeqProxy::sequence(6)),
                ApplyFlags::NONE,
                "journal",
                Ter::TES_SUCCESS,
            )
            .to_preclaim(9, Ter::TES_SUCCESS)
        },
        || ApplyResult::new(Ter::TES_SUCCESS, true, false),
        || sandbox_applied.set(true),
    );

    assert!(matches!(
        stage,
        QueueApplyFlowStage::ReturnTryClear {
            try_clear: QueueApplyTryClearStage::ApplySandboxAndReturn(ApplyResult {
                ter: Ter::TES_SUCCESS,
                applied: true,
                metadata_present: false,
            }),
            ..
        }
    ));
    assert_eq!(
        stage.apply_result(),
        ApplyResult::new(Ter::TES_SUCCESS, true, false)
    );
    assert!(sandbox_applied.get());
    assert!(views.accounts.is_empty());
}

