#[test]
fn txq_apply_flow_stage_caller_preclaim_boundary_exposes_prepared_preclaim() {
    let mut views = QueueViews::new(std::collections::BTreeMap::new(), vec![]);

    let stage = run_queue_apply_flow_stage_with_caller_preclaim(
        &mut views,
        SeqProxy::sequence(6),
        Some(MAYBE_TX_RETRIES_ALLOWED),
        QueueApplyHoldFallback::AlreadyVerifiedByMultiTxn,
        QueueApplyFullQueueDecision::Bypass,
        None,
        Some(250),
        ApplyFlags::RETRY,
        PreflightResult::new(
            "tx",
            None::<&str>,
            Rules::new(std::iter::empty()),
            TxConsequences::new(1, SeqProxy::sequence(6)),
            ApplyFlags::RETRY,
            "journal",
            Ter::TES_SUCCESS,
        ),
        &OrderCandidates::new(Uint256::from_u64(0)),
        QueueApplyPreparedPreclaimInputs::new(
            QueueApplyPreclaimViewSource::MultiTxnOpenView,
            110,
            50,
            100,
            4,
            Uint256::from_u64(9),
            "acct",
        ),
        |prepared| {
            assert_eq!(
                prepared,
                QueueApplyPreparedPreclaimInputs::new(
                    QueueApplyPreclaimViewSource::MultiTxnOpenView,
                    110,
                    50,
                    100,
                    4,
                    Uint256::from_u64(9),
                    "acct",
                )
            );

            Ok(QueueApplyPreclaimStage {
                view_source: prepared.view_source,
                trace_message: "trace".to_string(),
                preclaim_result: PreflightResult::new(
                    "tx",
                    None::<&str>,
                    Rules::new(std::iter::empty()),
                    TxConsequences::new(1, SeqProxy::sequence(6)),
                    ApplyFlags::RETRY,
                    "journal",
                    Ter::TES_SUCCESS,
                )
                .to_preclaim(9, Ter::TES_SUCCESS),
            })
        },
        || ApplyResult::new(Ter::TES_SUCCESS, true, false),
        || {},
    );

    assert!(matches!(
        stage,
        QueueApplyFlowStage::ReturnTryClear {
            preclaim: QueueApplyPreclaimStage {
                view_source: QueueApplyPreclaimViewSource::MultiTxnOpenView,
                ..
            },
            try_clear: QueueApplyTryClearStage::ApplySandboxAndReturn(ApplyResult {
                ter: Ter::TES_SUCCESS,
                applied: true,
                metadata_present: false,
            }),
        }
    ));
    assert_eq!(
        stage.apply_result(),
        ApplyResult::new(Ter::TES_SUCCESS, true, false)
    );
}

