#[test]
fn txq_try_clear_account_queue_up_thru_tx_returns_insufficient_fee() {
    let mut account = TxQAccount::new("acct");
    account.add(
        SeqProxy::sequence(5),
        MaybeTxCore::new(
            build_closed_ledger_maybe_tx("tx-5", "acct", SeqProxy::sequence(5), 5, 20, Some(120)),
            TxConsequences::new(1, SeqProxy::sequence(5)),
        ),
    );
    account.add(
        SeqProxy::sequence(6),
        MaybeTxCore::new(
            build_closed_ledger_maybe_tx("tx-6", "acct", SeqProxy::sequence(6), 6, 15, Some(120)),
            TxConsequences::new(1, SeqProxy::sequence(6)),
        ),
    );
    let queued_apply_calls = Cell::new(0);
    let current_apply_calls = Cell::new(0);

    let result = run_try_clear_account_queue_up_thru_tx(
        &mut account,
        SeqProxy::sequence(5),
        SeqProxy::sequence(8),
        10,
        |count| Some((count as u64) * 20),
        |_queued| {
            queued_apply_calls.set(queued_apply_calls.get() + 1);
            ApplyResult::new(Ter::TES_SUCCESS, true, true)
        },
        || {
            current_apply_calls.set(current_apply_calls.get() + 1);
            ApplyResult::new(Ter::TES_SUCCESS, true, true)
        },
    );

    assert_eq!(
        result,
        TryClearAccountResult::InsufficientFee {
            plan: tx::TryClearAccountPlan {
                queued_seq_proxies: vec![SeqProxy::sequence(5), SeqProxy::sequence(6)],
                queued_count: 2,
                target_was_already_queued: false,
                total_fee_level_paid: 45,
            },
            required_total_fee_level: 60,
        }
    );
    assert_eq!(
        result.apply_result(),
        ApplyResult::new(Ter::TEL_INSUF_FEE_P, false, false)
    );
    assert_eq!(queued_apply_calls.get(), 0);
    assert_eq!(current_apply_calls.get(), 0);
}

