#[test]
fn txq_apply_app_view_log_messages_match_runtime_envelope_app_view_boundary() {
    #[derive(Default)]
    struct TestApp {
        preflight_calls: usize,
        trace_messages: Vec<String>,
        direct_apply_calls: usize,
        prepare_multitxn_calls: usize,
        preclaim_calls: usize,
        try_clear_calls: usize,
        apply_sandbox_calls: usize,
    }

    impl tx::QueueApplyExecutionRuntime<&'static str, &'static str, &'static str> for TestApp {
        fn run_preflight(
            &mut self,
        ) -> PreflightResult<&'static str, TxConsequences, &'static str, &'static str> {
            self.preflight_calls += 1;
            PreflightResult::new(
                "tx",
                None::<&str>,
                Rules::new(std::iter::empty()),
                TxConsequences::new(1, SeqProxy::sequence(5)),
                ApplyFlags::FAIL_HARD | ApplyFlags::RETRY,
                "journal",
                Ter::TES_SUCCESS,
            )
        }

        fn trace(&mut self, message: &str) {
            self.trace_messages.push(message.to_owned());
        }

        fn direct_apply(&mut self) -> ApplyResult {
            self.direct_apply_calls += 1;
            ApplyResult::new(Ter::TES_SUCCESS, true, true)
        }

        fn prepare_multitxn(&mut self, _adjustment: QueueApplyViewAdjustment) -> bool {
            self.prepare_multitxn_calls += 1;
            true
        }

        fn run_preclaim(
            &mut self,
            view_source: QueueApplyPreclaimViewSource,
        ) -> PreclaimResult<&'static str, &'static str, &'static str> {
            self.preclaim_calls += 1;
            assert!(!view_source.has_multi_txn());
            PreclaimResult::new(
                100,
                "tx",
                None::<&str>,
                ApplyFlags::NONE,
                "journal",
                Ter::TES_SUCCESS,
            )
        }

        fn run_try_clear(&mut self) -> ApplyResult {
            self.try_clear_calls += 1;
            ApplyResult::new(Ter::TES_SUCCESS, true, true)
        }

        fn apply_sandbox(&mut self) {
            self.apply_sandbox_calls += 1;
        }
    }

    let rules = Rules::new(std::iter::empty());
    let account_id = String::from("acct");
    let tx_source = ParityObservedTxSource {
        account: &account_id,
        transaction_id: "ABC123",
        tx_id: Uint256::from_u64(9),
        tx_seq_proxy: SeqProxy::sequence(5),
    };
    let view_source = parity_direct_view(&rules);
    let snapshot = snapshot_queue_apply_app_view(&tx_source, &view_source);
    let call = QueueApplyCallEnvelope::new(&tx_source, &snapshot);
    let preflight_result = parity_queueing_preflight_result(&rules, SeqProxy::sequence(5));

    let mut runtime_shell = parity_build_direct_owner_shell();
    let mut runtime_app = TestApp::default();
    let runtime_stage = QueueApplyRuntimeEnvelope::new(&mut runtime_app)
        .apply_after_preflight_with_log_messages(
            &mut runtime_shell,
            &call,
            &preflight_result,
            QueueHoldPreflight::new(false, false, ApplyFlags::NONE, Some(250)),
            Ter::TES_SUCCESS,
        );

    let mut app_view_shell = parity_build_direct_owner_shell();
    let mut app = TestApp::default();
    let app_view_stage = run_queue_apply_after_preflight_with_app_view_and_log_messages(
        &mut app_view_shell,
        &mut app,
        &view_source,
        &tx_source,
        &preflight_result,
        QueueHoldPreflight::new(false, false, ApplyFlags::NONE, Some(250)),
        Ter::TES_SUCCESS,
    );

    assert_eq!(app_view_stage, runtime_stage);
    assert_eq!(app_view_shell.owner(), runtime_shell.owner());
    assert_eq!(app.preflight_calls, 0);
    assert_eq!(app.direct_apply_calls, 1);
    assert_eq!(app.prepare_multitxn_calls, 0);
    assert_eq!(app.preclaim_calls, 0);
    assert_eq!(app.try_clear_calls, 0);
    assert_eq!(app.apply_sandbox_calls, 0);
    assert_eq!(
        app.trace_messages,
        vec![
            format_direct_apply_start_log_message("ABC123"),
            format_direct_apply_finish_log_message(&DirectApplyExecution::<String, _> {
                transaction_id: "ABC123",
                attempt: DirectApplyAttemptResult {
                    apply_result: ApplyResult::new(Ter::TES_SUCCESS, true, true),
                    removed_replacement: None,
                },
            }),
        ]
    );
}

#[test]
fn txq_apply_app_view_matches_runtime_envelope_app_view_boundary() {
    #[derive(Default)]
    struct TestApp {
        preflight_calls: usize,
        trace_messages: Vec<String>,
        direct_apply_calls: usize,
        prepare_multitxn_calls: usize,
        preclaim_calls: usize,
        try_clear_calls: usize,
        apply_sandbox_calls: usize,
    }

    impl tx::QueueApplyExecutionRuntime<&'static str, &'static str, &'static str> for TestApp {
        fn run_preflight(
            &mut self,
        ) -> PreflightResult<&'static str, TxConsequences, &'static str, &'static str> {
            self.preflight_calls += 1;
            PreflightResult::new(
                "tx",
                None::<&str>,
                Rules::new(std::iter::empty()),
                TxConsequences::with_category(
                    1,
                    SeqProxy::sequence(6),
                    TxConsequencesCategory::Blocker,
                ),
                ApplyFlags::NONE,
                "journal",
                Ter::TES_SUCCESS,
            )
        }

        fn trace(&mut self, message: &str) {
            self.trace_messages.push(message.to_owned());
        }

        fn direct_apply(&mut self) -> ApplyResult {
            self.direct_apply_calls += 1;
            ApplyResult::new(Ter::TES_SUCCESS, true, true)
        }

        fn prepare_multitxn(&mut self, _adjustment: QueueApplyViewAdjustment) -> bool {
            self.prepare_multitxn_calls += 1;
            true
        }

        fn run_preclaim(
            &mut self,
            view_source: QueueApplyPreclaimViewSource,
        ) -> PreclaimResult<&'static str, &'static str, &'static str> {
            self.preclaim_calls += 1;
            assert!(!view_source.has_multi_txn());
            PreclaimResult::new(
                100,
                "tx",
                None::<&str>,
                ApplyFlags::NONE,
                "journal",
                Ter::TES_SUCCESS,
            )
        }

        fn run_try_clear(&mut self) -> ApplyResult {
            self.try_clear_calls += 1;
            ApplyResult::new(Ter::TES_SUCCESS, true, true)
        }

        fn apply_sandbox(&mut self) {
            self.apply_sandbox_calls += 1;
        }
    }

    let rules = Rules::new(std::iter::empty());
    let account_id = String::from("acct");
    let tx_source = ParityObservedTxSource {
        account: &account_id,
        transaction_id: "ABC123",
        tx_id: Uint256::from_u64(9),
        tx_seq_proxy: SeqProxy::sequence(6),
    };
    let view_source = ParityObservedViewSource {
        rules: rules.clone(),
        account_lookup: QueueApplyObservedAccountLookup::Present {
            sequence: 5,
            balance_drops: 1_000,
        },
        ticket_lookup: QueueApplyObservedTicketLookup::Present,
        calculated_base_fee_drops: 10,
        fee_paid_drops: 1,
        default_base_fee_drops: 10,
        metrics_snapshot: QueueFeeMetricsSnapshot {
            txns_expected: 32,
            escalation_multiplier: tx::TXQ_BASE_LEVEL * 500,
        },
        open_ledger_tx_count: 4,
        open_ledger_seq: 100,
        reserve_drops: 200,
        base_fee_drops: 10,
    };

    let build_views = || {
        let mut queued_account = TxQAccount::new(account_id.clone());
        queued_account.add(
            SeqProxy::sequence(5),
            MaybeTxCore::new(
                MaybeTx::new(
                    Uint256::from_u64(5),
                    90,
                    account_id.clone(),
                    Some(200),
                    SeqProxy::sequence(5),
                    ApplyFlags::NONE,
                    PreflightResult::new(
                        "tx",
                        None::<&str>,
                        rules.clone(),
                        TxConsequences::with_category(
                            1,
                            SeqProxy::sequence(5),
                            TxConsequencesCategory::Blocker,
                        ),
                        ApplyFlags::NONE,
                        "journal",
                        Ter::TES_SUCCESS,
                    ),
                ),
                TxConsequences::with_category(
                    1,
                    SeqProxy::sequence(5),
                    TxConsequencesCategory::Blocker,
                ),
            ),
        );
        QueueViews::new(
            std::collections::BTreeMap::from([(account_id.clone(), queued_account)]),
            vec![],
        )
    };

    let snapshot = snapshot_queue_apply_app_view(&tx_source, &view_source);
    let call = QueueApplyCallEnvelope::new(&tx_source, &snapshot);
    let mut runtime_shell = QueueApplyOwnerShell::new(QueueApplyLiveOwner::new(
        2,
        10,
        25,
        Some(10),
        OrderCandidates::new(Uint256::from_u64(0)),
        build_views(),
    ));
    let mut runtime_app = TestApp::default();
    let runtime_stage = QueueApplyRuntimeEnvelope::new(&mut runtime_app).apply(
        &mut runtime_shell,
        &call,
        QueueHoldPreflight::new(false, false, ApplyFlags::NONE, Some(250)),
        ApplyFlags::NONE,
        TxConsequences::with_category(1, SeqProxy::sequence(6), TxConsequencesCategory::Blocker),
        Ter::TES_SUCCESS,
    );

    let mut app_view_shell = QueueApplyOwnerShell::new(QueueApplyLiveOwner::new(
        2,
        10,
        25,
        Some(10),
        OrderCandidates::new(Uint256::from_u64(0)),
        build_views(),
    ));
    let mut app = TestApp::default();
    let app_view_stage = run_queue_apply_with_app_view(
        &mut app_view_shell,
        &mut app,
        &view_source,
        &tx_source,
        QueueHoldPreflight::new(false, false, ApplyFlags::NONE, Some(250)),
        ApplyFlags::NONE,
        TxConsequences::with_category(1, SeqProxy::sequence(6), TxConsequencesCategory::Blocker),
        Ter::TES_SUCCESS,
    );

    assert_eq!(app_view_stage, runtime_stage);
    assert_eq!(app_view_shell.owner(), runtime_shell.owner());
    assert_eq!(app.preflight_calls, 1);
    assert_eq!(app.direct_apply_calls, 0);
    assert_eq!(app.prepare_multitxn_calls, 0);
    assert_eq!(app.preclaim_calls, 0);
    assert_eq!(app.try_clear_calls, 0);
    assert_eq!(app.apply_sandbox_calls, 0);
    assert!(app.trace_messages.is_empty());
}

#[test]
fn txq_apply_hold_preflight_derivation_can_be_held_tx_fields() {
    #[derive(Debug)]
    struct DerivedTxSource<'a> {
        inner: ParityObservedTxSource<'a>,
        has_previous_txn_id: bool,
        has_account_txn_id: bool,
        last_valid_ledger: Option<u32>,
    }

    impl QueueApplyObservedTxSource for DerivedTxSource<'_> {
        type Account = String;
        type TransactionId = &'static str;

        fn account(&self) -> &Self::Account {
            self.inner.account()
        }

        fn transaction_id(&self) -> Self::TransactionId {
            self.inner.transaction_id()
        }

        fn tx_id(&self) -> Uint256 {
            self.inner.tx_id()
        }

        fn tx_seq_proxy(&self) -> SeqProxy {
            self.inner.tx_seq_proxy()
        }
    }

    impl QueueApplyHoldPreflightTxSource for DerivedTxSource<'_> {
        fn has_previous_txn_id(&self) -> bool {
            self.has_previous_txn_id
        }

        fn has_account_txn_id(&self) -> bool {
            self.has_account_txn_id
        }

        fn last_valid_ledger(&self) -> Option<u32> {
            self.last_valid_ledger
        }
    }

    let account_id = String::from("acct");
    let tx_source = DerivedTxSource {
        inner: ParityObservedTxSource {
            account: &account_id,
            transaction_id: "ABC123",
            tx_id: Uint256::from_u64(9),
            tx_seq_proxy: SeqProxy::sequence(6),
        },
        has_previous_txn_id: true,
        has_account_txn_id: true,
        last_valid_ledger: Some(250),
    };

    assert_eq!(
        derive_queue_hold_preflight_from_tx_source(
            &tx_source,
            ApplyFlags::FAIL_HARD | ApplyFlags::RETRY,
        ),
        QueueHoldPreflight::new(
            true,
            true,
            ApplyFlags::FAIL_HARD | ApplyFlags::RETRY,
            Some(250),
        )
    );
}

