#[test]
fn txq_apply_journal_envelope_caller_preclaim_matches_app_view_journal_boundary() {
    let rules = Rules::new(std::iter::empty());
    let account_id = String::from("a");
    let tx_source = ParityObservedTxSource {
        account: &account_id,
        transaction_id: "ABC123",
        tx_id: Uint256::from_u64(9),
        tx_seq_proxy: SeqProxy::sequence(6),
    };
    let view_source = parity_queueing_view(&rules);
    let preflight_result = parity_queueing_preflight_result(&rules, SeqProxy::sequence(6));
    let expected_prepared = RefCell::new(None::<QueueApplyPreparedPreclaimInputs<String>>);

    let mut free_owner = parity_build_full_queue_owner_shell(&rules);
    let mut free_app = ParityCallerPreclaimApp::new(preflight_result.clone());
    let free_emitted = RefCell::new(Vec::new());
    let free_stage = run_queue_apply_with_app_view_and_caller_preclaim_and_log_sinks(
        &mut free_owner,
        &mut free_app,
        &view_source,
        &tx_source,
        QueueHoldPreflight::new(false, false, ApplyFlags::NONE, Some(250)),
        ApplyFlags::FAIL_HARD | ApplyFlags::RETRY,
        preflight_result.clone().consequences,
        Ter::TES_SUCCESS,
        |prepared| {
            expected_prepared.replace(Some(prepared.clone()));
            Ok(parity_caller_preclaim_stage(prepared, &preflight_result))
        },
        |message| free_emitted.borrow_mut().push(format!("trace:{message}")),
        |message| free_emitted.borrow_mut().push(format!("debug:{message}")),
        |message| free_emitted.borrow_mut().push(format!("info:{message}")),
    );

    let mut journal_owner = parity_build_full_queue_owner_shell(&rules);
    let mut journal_app = ParityCallerPreclaimApp::new(preflight_result.clone());
    let mut journal = ParityJournalSink::default();
    let mut envelope = QueueApplyJournalEnvelope::new(&mut journal_app, &view_source, &mut journal);
    let journal_stage = envelope.apply_with_caller_preclaim(
        &mut journal_owner,
        &tx_source,
        QueueHoldPreflight::new(false, false, ApplyFlags::NONE, Some(250)),
        ApplyFlags::FAIL_HARD | ApplyFlags::RETRY,
        preflight_result.clone().consequences,
        Ter::TES_SUCCESS,
        |prepared| {
            assert_eq!(Some(prepared.clone()), *expected_prepared.borrow());
            Ok(parity_caller_preclaim_stage(prepared, &preflight_result))
        },
    );

    assert_eq!(journal_stage, free_stage);
    assert_eq!(journal_owner.owner(), free_owner.owner());
    assert_eq!(journal.emitted, free_emitted.into_inner());
    assert_eq!(journal_app.preflight_calls, 1);
    assert_eq!(journal_app.prepare_multitxn_calls, 1);
    assert_eq!(journal_app.preclaim_calls, 0);
}

