#[test]
fn txq_apply_journal_owner_matches_journal_envelope_owner_plus_journal_boundary() {
    #[derive(Default)]
    struct TestApp {
        preflight_calls: usize,
        trace_messages: Vec<String>,
        direct_apply_calls: usize,
        prepare_multitxn_calls: usize,
        preclaim_calls: usize,
        try_clear_calls: usize,
        apply_sandbox_calls: usize,
    }

    impl tx::QueueApplyExecutionRuntime<&'static str, &'static str, &'static str> for TestApp {
        fn run_preflight(
            &mut self,
        ) -> PreflightResult<&'static str, TxConsequences, &'static str, &'static str> {
            self.preflight_calls += 1;
            PreflightResult::new(
                "tx",
                None::<&str>,
                Rules::new(std::iter::empty()),
                TxConsequences::new(1, SeqProxy::sequence(6)),
                ApplyFlags::FAIL_HARD | ApplyFlags::RETRY,
                "journal",
                Ter::TES_SUCCESS,
            )
        }

        fn trace(&mut self, message: &str) {
            self.trace_messages.push(message.to_owned());
        }

        fn direct_apply(&mut self) -> ApplyResult {
            self.direct_apply_calls += 1;
            ApplyResult::new(Ter::TES_SUCCESS, true, true)
        }

        fn prepare_multitxn(&mut self, _adjustment: QueueApplyViewAdjustment) -> bool {
            self.prepare_multitxn_calls += 1;
            true
        }

        fn run_preclaim(
            &mut self,
            _view_source: QueueApplyPreclaimViewSource,
        ) -> PreclaimResult<&'static str, &'static str, &'static str> {
            self.preclaim_calls += 1;
            PreclaimResult::new(
                100,
                "tx",
                None::<&str>,
                ApplyFlags::NONE,
                "journal",
                Ter::TES_SUCCESS,
            )
        }

        fn run_try_clear(&mut self) -> ApplyResult {
            self.try_clear_calls += 1;
            ApplyResult::new(Ter::TES_SUCCESS, true, true)
        }

        fn apply_sandbox(&mut self) {
            self.apply_sandbox_calls += 1;
        }
    }

    #[derive(Default, Debug, Clone, PartialEq, Eq)]
    struct TestJournal {
        emitted: Vec<String>,
    }

    impl QueueApplyJournalSink for TestJournal {
        fn trace(&mut self, message: &str) {
            self.emitted.push(format!("trace:{message}"));
        }

        fn debug(&mut self, message: &str) {
            self.emitted.push(format!("debug:{message}"));
        }

        fn info(&mut self, message: &str) {
            self.emitted.push(format!("info:{message}"));
        }
    }

    let rules = Rules::new(std::iter::empty());
    let account_a = String::from("a");
    let account_b = String::from("b");
    let tx_source = ParityObservedTxSource {
        account: &account_a,
        transaction_id: "ABC123",
        tx_id: Uint256::from_u64(9),
        tx_seq_proxy: SeqProxy::sequence(6),
    };
    let view_source = ParityObservedViewSource {
        rules: rules.clone(),
        account_lookup: QueueApplyObservedAccountLookup::Present {
            sequence: 5,
            balance_drops: 1_000,
        },
        ticket_lookup: QueueApplyObservedTicketLookup::Missing,
        calculated_base_fee_drops: 10,
        fee_paid_drops: 10,
        default_base_fee_drops: 10,
        metrics_snapshot: QueueFeeMetricsSnapshot {
            txns_expected: 32,
            escalation_multiplier: tx::TXQ_BASE_LEVEL * 500,
        },
        open_ledger_tx_count: 4,
        open_ledger_seq: 100,
        reserve_drops: 200,
        base_fee_drops: 10,
    };

    let build_views = || {
        let mut queued_a = TxQAccount::new(account_a.clone());
        queued_a.add(
            SeqProxy::sequence(5),
            MaybeTxCore::new(
                MaybeTx::new(
                    Uint256::from_u64(5),
                    90,
                    account_a.clone(),
                    Some(200),
                    SeqProxy::sequence(5),
                    ApplyFlags::NONE,
                    PreflightResult::new(
                        "tx",
                        None::<&str>,
                        rules.clone(),
                        TxConsequences::new(1, SeqProxy::sequence(5)),
                        ApplyFlags::NONE,
                        "journal",
                        Ter::TES_SUCCESS,
                    ),
                ),
                TxConsequences::new(1, SeqProxy::sequence(5)),
            ),
        );

        let mut queued_b = TxQAccount::new(account_b.clone());
        queued_b.add(
            SeqProxy::sequence(8),
            MaybeTxCore::new(
                MaybeTx::new(
                    Uint256::from_u64(8),
                    50,
                    account_b.clone(),
                    Some(200),
                    SeqProxy::sequence(8),
                    ApplyFlags::NONE,
                    PreflightResult::new(
                        "tx",
                        None::<&str>,
                        rules.clone(),
                        TxConsequences::new(1, SeqProxy::sequence(8)),
                        ApplyFlags::NONE,
                        "journal",
                        Ter::TES_SUCCESS,
                    ),
                ),
                TxConsequences::new(1, SeqProxy::sequence(8)),
            ),
        );

        QueueViews::new(
            std::collections::BTreeMap::from([
                (account_a.clone(), queued_a),
                (account_b.clone(), queued_b),
            ]),
            vec![
                FeeQueueEntry::new(
                    FeeQueueKey::new(account_a.clone(), SeqProxy::sequence(5)),
                    QueueAdvanceCandidate {
                        fee_level: 90,
                        tx_id: Uint256::from_u64(5),
                        seq_proxy: SeqProxy::sequence(5),
                    },
                ),
                FeeQueueEntry::new(
                    FeeQueueKey::new(account_b.clone(), SeqProxy::sequence(8)),
                    QueueAdvanceCandidate {
                        fee_level: 50,
                        tx_id: Uint256::from_u64(8),
                        seq_proxy: SeqProxy::sequence(8),
                    },
                ),
            ],
        )
    };

    let mut journal_envelope_owner = QueueApplyOwnerShell::new(QueueApplyLiveOwner::new(
        2,
        10,
        25,
        Some(2),
        OrderCandidates::new(Uint256::from_u64(0)),
        build_views(),
    ));
    let mut journal_envelope_app = TestApp::default();
    let mut envelope_journal = TestJournal::default();
    let mut envelope = QueueApplyJournalEnvelope::new(
        &mut journal_envelope_app,
        &view_source,
        &mut envelope_journal,
    );
    let envelope_stage = envelope.apply(
        &mut journal_envelope_owner,
        &tx_source,
        QueueHoldPreflight::new(false, false, ApplyFlags::NONE, Some(250)),
        ApplyFlags::FAIL_HARD | ApplyFlags::RETRY,
        TxConsequences::new(1, SeqProxy::sequence(6)),
        Ter::TES_SUCCESS,
    );

    let mut journal_owner = QueueApplyJournalOwner::new(
        QueueApplyOwnerShell::new(QueueApplyLiveOwner::new(
            2,
            10,
            25,
            Some(2),
            OrderCandidates::new(Uint256::from_u64(0)),
            build_views(),
        )),
        TestJournal::default(),
    );
    let mut owner_app = TestApp::default();
    let owner_stage = journal_owner.apply(
        &mut owner_app,
        &view_source,
        &tx_source,
        QueueHoldPreflight::new(false, false, ApplyFlags::NONE, Some(250)),
        ApplyFlags::FAIL_HARD | ApplyFlags::RETRY,
        TxConsequences::new(1, SeqProxy::sequence(6)),
        Ter::TES_SUCCESS,
    );

    assert_eq!(owner_stage, envelope_stage);
    assert_eq!(journal_owner.owner(), &journal_envelope_owner);
    assert_eq!(journal_owner.journal(), &envelope_journal);
    assert_eq!(journal_envelope_app.preflight_calls, 1);
    assert_eq!(owner_app.preflight_calls, 1);
    assert_eq!(journal_envelope_app.direct_apply_calls, 0);
    assert_eq!(owner_app.direct_apply_calls, 0);
    assert_eq!(journal_envelope_app.prepare_multitxn_calls, 1);
    assert_eq!(owner_app.prepare_multitxn_calls, 1);
    assert_eq!(journal_envelope_app.preclaim_calls, 1);
    assert_eq!(owner_app.preclaim_calls, 1);
}

