#[test]
fn txq_apply_journal_owner_caller_preclaim_matches_journal_envelope_owner_plus_journal_boundary() {
    let rules = Rules::new(std::iter::empty());
    let account_id = String::from("a");
    let tx_source = ParityObservedTxSource {
        account: &account_id,
        transaction_id: "ABC123",
        tx_id: Uint256::from_u64(9),
        tx_seq_proxy: SeqProxy::sequence(6),
    };
    let view_source = parity_queueing_view(&rules);
    let preflight_result = parity_queueing_preflight_result(&rules, SeqProxy::sequence(6));
    let expected_prepared = RefCell::new(None::<QueueApplyPreparedPreclaimInputs<String>>);

    let mut journal_envelope_owner = parity_build_full_queue_owner_shell(&rules);
    let mut journal_envelope_app = ParityCallerPreclaimApp::new(preflight_result.clone());
    let mut envelope_journal = ParityJournalSink::default();
    let mut envelope = QueueApplyJournalEnvelope::new(
        &mut journal_envelope_app,
        &view_source,
        &mut envelope_journal,
    );
    let envelope_stage = envelope.apply_with_caller_preclaim(
        &mut journal_envelope_owner,
        &tx_source,
        QueueHoldPreflight::new(false, false, ApplyFlags::NONE, Some(250)),
        ApplyFlags::FAIL_HARD | ApplyFlags::RETRY,
        preflight_result.clone().consequences,
        Ter::TES_SUCCESS,
        |prepared| {
            expected_prepared.replace(Some(prepared.clone()));
            Ok(parity_caller_preclaim_stage(prepared, &preflight_result))
        },
    );

    let mut journal_owner = parity_build_full_queue_owner_shell(&rules)
        .into_journal_owner(ParityJournalSink::default());
    let mut owner_app = ParityCallerPreclaimApp::new(preflight_result.clone());
    let owner_stage = journal_owner.apply_with_caller_preclaim(
        &mut owner_app,
        &view_source,
        &tx_source,
        QueueHoldPreflight::new(false, false, ApplyFlags::NONE, Some(250)),
        ApplyFlags::FAIL_HARD | ApplyFlags::RETRY,
        preflight_result.clone().consequences,
        Ter::TES_SUCCESS,
        |prepared| {
            assert_eq!(Some(prepared.clone()), *expected_prepared.borrow());
            Ok(parity_caller_preclaim_stage(prepared, &preflight_result))
        },
    );

    assert_eq!(owner_stage, envelope_stage);
    assert_eq!(journal_owner.owner(), &journal_envelope_owner);
    assert_eq!(journal_owner.journal(), &envelope_journal);
    assert_eq!(owner_app.preclaim_calls, 0);
}

