#[test]
fn txq_apply_journal_owner_after_preflight_matches_journal_envelope_owner_plus_journal_boundary() {
    #[derive(Default)]
    struct TestApp {
        preflight_calls: usize,
        trace_messages: Vec<String>,
        direct_apply_calls: usize,
        prepare_multitxn_calls: usize,
        preclaim_calls: usize,
        try_clear_calls: usize,
        apply_sandbox_calls: usize,
    }

    impl tx::QueueApplyExecutionRuntime<&'static str, &'static str, &'static str> for TestApp {
        fn run_preflight(
            &mut self,
        ) -> PreflightResult<&'static str, TxConsequences, &'static str, &'static str> {
            self.preflight_calls += 1;
            PreflightResult::new(
                "tx",
                None::<&str>,
                Rules::new(std::iter::empty()),
                TxConsequences::new(1, SeqProxy::sequence(5)),
                ApplyFlags::FAIL_HARD | ApplyFlags::RETRY,
                "journal",
                Ter::TES_SUCCESS,
            )
        }

        fn trace(&mut self, message: &str) {
            self.trace_messages.push(message.to_owned());
        }

        fn direct_apply(&mut self) -> ApplyResult {
            self.direct_apply_calls += 1;
            ApplyResult::new(Ter::TES_SUCCESS, true, true)
        }

        fn prepare_multitxn(&mut self, _adjustment: QueueApplyViewAdjustment) -> bool {
            self.prepare_multitxn_calls += 1;
            true
        }

        fn run_preclaim(
            &mut self,
            _view_source: QueueApplyPreclaimViewSource,
        ) -> PreclaimResult<&'static str, &'static str, &'static str> {
            self.preclaim_calls += 1;
            PreclaimResult::new(
                100,
                "tx",
                None::<&str>,
                ApplyFlags::NONE,
                "journal",
                Ter::TES_SUCCESS,
            )
        }

        fn run_try_clear(&mut self) -> ApplyResult {
            self.try_clear_calls += 1;
            ApplyResult::new(Ter::TES_SUCCESS, true, true)
        }

        fn apply_sandbox(&mut self) {
            self.apply_sandbox_calls += 1;
        }
    }

    #[derive(Default, Debug, Clone, PartialEq, Eq)]
    struct TestJournal {
        emitted: Vec<String>,
    }

    impl QueueApplyJournalSink for TestJournal {
        fn trace(&mut self, message: &str) {
            self.emitted.push(format!("trace:{message}"));
        }

        fn debug(&mut self, message: &str) {
            self.emitted.push(format!("debug:{message}"));
        }

        fn info(&mut self, message: &str) {
            self.emitted.push(format!("info:{message}"));
        }
    }

    let rules = Rules::new(std::iter::empty());
    let account_id = String::from("a");
    let tx_source = ParityObservedTxSource {
        account: &account_id,
        transaction_id: "ABC123",
        tx_id: Uint256::from_u64(9),
        tx_seq_proxy: SeqProxy::sequence(5),
    };
    let view_source = ParityObservedViewSource {
        rules: rules.clone(),
        account_lookup: QueueApplyObservedAccountLookup::Present {
            sequence: 5,
            balance_drops: 1_000,
        },
        ticket_lookup: QueueApplyObservedTicketLookup::Missing,
        calculated_base_fee_drops: 10,
        fee_paid_drops: 100,
        default_base_fee_drops: 10,
        metrics_snapshot: QueueFeeMetricsSnapshot {
            txns_expected: 32,
            escalation_multiplier: tx::TXQ_BASE_LEVEL,
        },
        open_ledger_tx_count: 4,
        open_ledger_seq: 100,
        reserve_drops: 200,
        base_fee_drops: 10,
    };
    let preflight_result = PreflightResult::new(
        "tx",
        None::<&str>,
        rules,
        TxConsequences::new(1, SeqProxy::sequence(5)),
        ApplyFlags::FAIL_HARD | ApplyFlags::RETRY,
        "journal",
        Ter::TES_SUCCESS,
    );

    let build_views = || {
        QueueViews::<String, MaybeTx<&'static str, String, &'static str, &'static str>>::new(
            std::collections::BTreeMap::new(),
            Vec::new(),
        )
    };

    let mut journal_envelope_owner = QueueApplyOwnerShell::new(QueueApplyLiveOwner::new(
        2,
        10,
        25,
        Some(10),
        OrderCandidates::new(Uint256::from_u64(0)),
        build_views(),
    ));
    let mut journal_envelope_app = TestApp::default();
    let mut envelope_journal = TestJournal::default();
    let mut envelope = QueueApplyJournalEnvelope::new(
        &mut journal_envelope_app,
        &view_source,
        &mut envelope_journal,
    );
    let envelope_stage = envelope.apply_after_preflight(
        &mut journal_envelope_owner,
        &tx_source,
        &preflight_result,
        QueueHoldPreflight::new(false, false, ApplyFlags::NONE, Some(250)),
        Ter::TES_SUCCESS,
    );

    let mut journal_owner = QueueApplyJournalOwner::new(
        QueueApplyOwnerShell::new(QueueApplyLiveOwner::new(
            2,
            10,
            25,
            Some(10),
            OrderCandidates::new(Uint256::from_u64(0)),
            build_views(),
        )),
        TestJournal::default(),
    );
    let mut owner_app = TestApp::default();
    let owner_stage = journal_owner.apply_after_preflight(
        &mut owner_app,
        &view_source,
        &tx_source,
        &preflight_result,
        QueueHoldPreflight::new(false, false, ApplyFlags::NONE, Some(250)),
        Ter::TES_SUCCESS,
    );

    let expected_emitted = vec![
        format!("trace:{}", format_direct_apply_start_log_message("ABC123")),
        format!(
            "trace:{}",
            format_direct_apply_finish_log_message(&DirectApplyExecution::<String, _> {
                transaction_id: "ABC123",
                attempt: DirectApplyAttemptResult {
                    apply_result: ApplyResult::new(Ter::TES_SUCCESS, true, true),
                    removed_replacement: None,
                },
            })
        ),
    ];

    assert_eq!(owner_stage, envelope_stage);
    assert_eq!(journal_owner.owner(), &journal_envelope_owner);
    assert_eq!(journal_owner.journal(), &envelope_journal);
    assert_eq!(journal_owner.journal().emitted, expected_emitted);
    assert_eq!(journal_envelope_app.preflight_calls, 0);
    assert_eq!(owner_app.preflight_calls, 0);
    assert_eq!(journal_envelope_app.direct_apply_calls, 1);
    assert_eq!(owner_app.direct_apply_calls, 1);
}

#[test]
fn txq_apply_owner_shell_app_view_method_matches_free_wrapper_member_boundary() {
    #[derive(Default)]
    struct TestApp {
        preflight_calls: usize,
        trace_messages: Vec<String>,
        direct_apply_calls: usize,
        prepare_multitxn_calls: usize,
        preclaim_calls: usize,
        try_clear_calls: usize,
        apply_sandbox_calls: usize,
    }

    impl tx::QueueApplyExecutionRuntime<&'static str, &'static str, &'static str> for TestApp {
        fn run_preflight(
            &mut self,
        ) -> PreflightResult<&'static str, TxConsequences, &'static str, &'static str> {
            self.preflight_calls += 1;
            PreflightResult::new(
                "tx",
                None::<&str>,
                Rules::new(std::iter::empty()),
                TxConsequences::with_category(
                    1,
                    SeqProxy::sequence(6),
                    TxConsequencesCategory::Blocker,
                ),
                ApplyFlags::NONE,
                "journal",
                Ter::TES_SUCCESS,
            )
        }

        fn trace(&mut self, message: &str) {
            self.trace_messages.push(message.to_owned());
        }

        fn direct_apply(&mut self) -> ApplyResult {
            self.direct_apply_calls += 1;
            ApplyResult::new(Ter::TES_SUCCESS, true, true)
        }

        fn prepare_multitxn(&mut self, _adjustment: QueueApplyViewAdjustment) -> bool {
            self.prepare_multitxn_calls += 1;
            true
        }

        fn run_preclaim(
            &mut self,
            view_source: QueueApplyPreclaimViewSource,
        ) -> PreclaimResult<&'static str, &'static str, &'static str> {
            self.preclaim_calls += 1;
            assert!(!view_source.has_multi_txn());
            PreclaimResult::new(
                100,
                "tx",
                None::<&str>,
                ApplyFlags::NONE,
                "journal",
                Ter::TES_SUCCESS,
            )
        }

        fn run_try_clear(&mut self) -> ApplyResult {
            self.try_clear_calls += 1;
            ApplyResult::new(Ter::TES_SUCCESS, true, true)
        }

        fn apply_sandbox(&mut self) {
            self.apply_sandbox_calls += 1;
        }
    }

    let rules = Rules::new(std::iter::empty());
    let account_id = String::from("acct");
    let tx_source = ParityObservedTxSource {
        account: &account_id,
        transaction_id: "ABC123",
        tx_id: Uint256::from_u64(9),
        tx_seq_proxy: SeqProxy::sequence(6),
    };
    let view_source = ParityObservedViewSource {
        rules: rules.clone(),
        account_lookup: QueueApplyObservedAccountLookup::Present {
            sequence: 5,
            balance_drops: 1_000,
        },
        ticket_lookup: QueueApplyObservedTicketLookup::Present,
        calculated_base_fee_drops: 10,
        fee_paid_drops: 1,
        default_base_fee_drops: 10,
        metrics_snapshot: QueueFeeMetricsSnapshot {
            txns_expected: 32,
            escalation_multiplier: tx::TXQ_BASE_LEVEL * 500,
        },
        open_ledger_tx_count: 4,
        open_ledger_seq: 100,
        reserve_drops: 200,
        base_fee_drops: 10,
    };

    let build_views = || {
        let mut queued_account = TxQAccount::new(account_id.clone());
        queued_account.add(
            SeqProxy::sequence(5),
            MaybeTxCore::new(
                MaybeTx::new(
                    Uint256::from_u64(5),
                    90,
                    account_id.clone(),
                    Some(200),
                    SeqProxy::sequence(5),
                    ApplyFlags::NONE,
                    PreflightResult::new(
                        "tx",
                        None::<&str>,
                        rules.clone(),
                        TxConsequences::with_category(
                            1,
                            SeqProxy::sequence(5),
                            TxConsequencesCategory::Blocker,
                        ),
                        ApplyFlags::NONE,
                        "journal",
                        Ter::TES_SUCCESS,
                    ),
                ),
                TxConsequences::with_category(
                    1,
                    SeqProxy::sequence(5),
                    TxConsequencesCategory::Blocker,
                ),
            ),
        );
        QueueViews::new(
            std::collections::BTreeMap::from([(account_id.clone(), queued_account)]),
            vec![],
        )
    };

    let mut free_shell = QueueApplyOwnerShell::new(QueueApplyLiveOwner::new(
        2,
        10,
        25,
        Some(10),
        OrderCandidates::new(Uint256::from_u64(0)),
        build_views(),
    ));
    let mut free_app = TestApp::default();
    let free_stage = run_queue_apply_with_app_view(
        &mut free_shell,
        &mut free_app,
        &view_source,
        &tx_source,
        QueueHoldPreflight::new(false, false, ApplyFlags::NONE, Some(250)),
        ApplyFlags::NONE,
        TxConsequences::with_category(1, SeqProxy::sequence(6), TxConsequencesCategory::Blocker),
        Ter::TES_SUCCESS,
    );

    let mut method_shell = QueueApplyOwnerShell::new(QueueApplyLiveOwner::new(
        2,
        10,
        25,
        Some(10),
        OrderCandidates::new(Uint256::from_u64(0)),
        build_views(),
    ));
    let mut method_app = TestApp::default();
    let method_stage = method_shell.apply_with_app_view(
        &mut method_app,
        &view_source,
        &tx_source,
        QueueHoldPreflight::new(false, false, ApplyFlags::NONE, Some(250)),
        ApplyFlags::NONE,
        TxConsequences::with_category(1, SeqProxy::sequence(6), TxConsequencesCategory::Blocker),
        Ter::TES_SUCCESS,
    );

    assert_eq!(method_stage, free_stage);
    assert_eq!(method_shell.owner(), free_shell.owner());
    assert_eq!(method_app.preflight_calls, 1);
    assert_eq!(method_app.direct_apply_calls, 0);
    assert_eq!(method_app.prepare_multitxn_calls, 0);
    assert_eq!(method_app.preclaim_calls, 0);
    assert_eq!(method_app.try_clear_calls, 0);
    assert_eq!(method_app.apply_sandbox_calls, 0);
    assert!(method_app.trace_messages.is_empty());
}

#[test]
fn txq_apply_owner_shell_app_view_owned_metrics_match_explicit_snapshot_member_boundary() {
    let rules = Rules::new(std::iter::empty());
    let account_id = String::from("a");
    let tx_source = ParityObservedTxSource {
        account: &account_id,
        transaction_id: "ABC123",
        tx_id: Uint256::from_u64(9),
        tx_seq_proxy: SeqProxy::sequence(5),
    };
    let mut view_source = parity_direct_view(&rules);
    view_source.metrics_snapshot = QueueFeeMetricsSnapshot {
        txns_expected: 256,
        escalation_multiplier: TXQ_BASE_LEVEL,
    };
    view_source.open_ledger_tx_count = 40;
    let hold_preflight = QueueHoldPreflight::new(
        false,
        false,
        ApplyFlags::FAIL_HARD | ApplyFlags::RETRY,
        Some(250),
    );

    let mut free_shell = parity_build_direct_owner_shell();
    let free_snapshot = free_shell.owner().metrics().snapshot();
    let mut free_app = parity_queueing_app(&rules, SeqProxy::sequence(5));
    let free_stage = run_queue_apply_with_app_view_and_metrics_snapshot(
        &mut free_shell,
        &mut free_app,
        &view_source,
        &tx_source,
        free_snapshot,
        hold_preflight,
        ApplyFlags::FAIL_HARD | ApplyFlags::RETRY,
        TxConsequences::new(1, SeqProxy::sequence(5)),
        Ter::TES_SUCCESS,
    );

    let mut plain_shell = parity_build_direct_owner_shell();
    let mut plain_app = parity_queueing_app(&rules, SeqProxy::sequence(5));
    let plain_stage = run_queue_apply_with_app_view(
        &mut plain_shell,
        &mut plain_app,
        &view_source,
        &tx_source,
        hold_preflight,
        ApplyFlags::FAIL_HARD | ApplyFlags::RETRY,
        TxConsequences::new(1, SeqProxy::sequence(5)),
        Ter::TES_SUCCESS,
    );

    let mut method_shell = parity_build_direct_owner_shell();
    let mut method_app = parity_queueing_app(&rules, SeqProxy::sequence(5));
    let method_stage = method_shell.apply_with_app_view_and_owned_metrics(
        &mut method_app,
        &view_source,
        &tx_source,
        hold_preflight,
        ApplyFlags::FAIL_HARD | ApplyFlags::RETRY,
        TxConsequences::new(1, SeqProxy::sequence(5)),
        Ter::TES_SUCCESS,
    );

    assert_eq!(method_stage, free_stage);
    assert_eq!(method_shell.owner(), free_shell.owner());
    assert_ne!(plain_stage, method_stage);
    assert_eq!(plain_app.direct_apply_calls, 1);
    assert_eq!(method_app.direct_apply_calls, 0);
}

#[test]
fn txq_apply_owner_shell_app_view_after_preflight_method_matches_free_wrapper_member_boundary() {
    #[derive(Default)]
    struct TestApp {
        preflight_calls: usize,
        trace_messages: Vec<String>,
        direct_apply_calls: usize,
        prepare_multitxn_calls: usize,
        preclaim_calls: usize,
        try_clear_calls: usize,
        apply_sandbox_calls: usize,
    }

    impl tx::QueueApplyExecutionRuntime<&'static str, &'static str, &'static str> for TestApp {
        fn run_preflight(
            &mut self,
        ) -> PreflightResult<&'static str, TxConsequences, &'static str, &'static str> {
            self.preflight_calls += 1;
            PreflightResult::new(
                "tx",
                None::<&str>,
                Rules::new(std::iter::empty()),
                TxConsequences::with_category(
                    1,
                    SeqProxy::sequence(6),
                    TxConsequencesCategory::Blocker,
                ),
                ApplyFlags::NONE,
                "journal",
                Ter::TES_SUCCESS,
            )
        }

        fn trace(&mut self, message: &str) {
            self.trace_messages.push(message.to_owned());
        }

        fn direct_apply(&mut self) -> ApplyResult {
            self.direct_apply_calls += 1;
            ApplyResult::new(Ter::TES_SUCCESS, true, true)
        }

        fn prepare_multitxn(&mut self, _adjustment: QueueApplyViewAdjustment) -> bool {
            self.prepare_multitxn_calls += 1;
            true
        }

        fn run_preclaim(
            &mut self,
            view_source: QueueApplyPreclaimViewSource,
        ) -> PreclaimResult<&'static str, &'static str, &'static str> {
            self.preclaim_calls += 1;
            assert!(!view_source.has_multi_txn());
            PreclaimResult::new(
                100,
                "tx",
                None::<&str>,
                ApplyFlags::NONE,
                "journal",
                Ter::TES_SUCCESS,
            )
        }

        fn run_try_clear(&mut self) -> ApplyResult {
            self.try_clear_calls += 1;
            ApplyResult::new(Ter::TES_SUCCESS, true, true)
        }

        fn apply_sandbox(&mut self) {
            self.apply_sandbox_calls += 1;
        }
    }

    let rules = Rules::new(std::iter::empty());
    let account_id = String::from("acct");
    let tx_source = ParityObservedTxSource {
        account: &account_id,
        transaction_id: "ABC123",
        tx_id: Uint256::from_u64(9),
        tx_seq_proxy: SeqProxy::sequence(6),
    };
    let view_source = ParityObservedViewSource {
        rules: rules.clone(),
        account_lookup: QueueApplyObservedAccountLookup::Present {
            sequence: 5,
            balance_drops: 1_000,
        },
        ticket_lookup: QueueApplyObservedTicketLookup::Present,
        calculated_base_fee_drops: 10,
        fee_paid_drops: 1,
        default_base_fee_drops: 10,
        metrics_snapshot: QueueFeeMetricsSnapshot {
            txns_expected: 32,
            escalation_multiplier: tx::TXQ_BASE_LEVEL * 500,
        },
        open_ledger_tx_count: 4,
        open_ledger_seq: 100,
        reserve_drops: 200,
        base_fee_drops: 10,
    };
    let preflight_result = PreflightResult::new(
        "tx",
        None::<&str>,
        rules.clone(),
        TxConsequences::with_category(1, SeqProxy::sequence(6), TxConsequencesCategory::Blocker),
        ApplyFlags::NONE,
        "journal",
        Ter::TES_SUCCESS,
    );

    let build_views = || {
        let mut queued_account = TxQAccount::new(account_id.clone());
        queued_account.add(
            SeqProxy::sequence(5),
            MaybeTxCore::new(
                MaybeTx::new(
                    Uint256::from_u64(5),
                    90,
                    account_id.clone(),
                    Some(200),
                    SeqProxy::sequence(5),
                    ApplyFlags::NONE,
                    PreflightResult::new(
                        "tx",
                        None::<&str>,
                        rules.clone(),
                        TxConsequences::with_category(
                            1,
                            SeqProxy::sequence(5),
                            TxConsequencesCategory::Blocker,
                        ),
                        ApplyFlags::NONE,
                        "journal",
                        Ter::TES_SUCCESS,
                    ),
                ),
                TxConsequences::with_category(
                    1,
                    SeqProxy::sequence(5),
                    TxConsequencesCategory::Blocker,
                ),
            ),
        );
        QueueViews::new(
            std::collections::BTreeMap::from([(account_id.clone(), queued_account)]),
            vec![],
        )
    };

    let mut free_shell = QueueApplyOwnerShell::new(QueueApplyLiveOwner::new(
        2,
        10,
        25,
        Some(10),
        OrderCandidates::new(Uint256::from_u64(0)),
        build_views(),
    ));
    let mut free_app = TestApp::default();
    let free_stage = run_queue_apply_after_preflight_with_app_view(
        &mut free_shell,
        &mut free_app,
        &view_source,
        &tx_source,
        &preflight_result,
        QueueHoldPreflight::new(false, false, ApplyFlags::NONE, Some(250)),
        Ter::TES_SUCCESS,
    );

    let mut method_shell = QueueApplyOwnerShell::new(QueueApplyLiveOwner::new(
        2,
        10,
        25,
        Some(10),
        OrderCandidates::new(Uint256::from_u64(0)),
        build_views(),
    ));
    let mut method_app = TestApp::default();
    let method_stage = method_shell.apply_after_preflight_with_app_view(
        &mut method_app,
        &view_source,
        &tx_source,
        &preflight_result,
        QueueHoldPreflight::new(false, false, ApplyFlags::NONE, Some(250)),
        Ter::TES_SUCCESS,
    );

    assert_eq!(method_stage, free_stage);
    assert_eq!(method_shell.owner(), free_shell.owner());
    assert_eq!(method_app.preflight_calls, 0);
    assert_eq!(method_app.direct_apply_calls, 0);
    assert_eq!(method_app.prepare_multitxn_calls, 0);
    assert_eq!(method_app.preclaim_calls, 0);
    assert_eq!(method_app.try_clear_calls, 0);
    assert_eq!(method_app.apply_sandbox_calls, 0);
    assert!(method_app.trace_messages.is_empty());
}

