fn parity_build_full_queue_views(
    rules: &Rules,
) -> QueueViews<String, MaybeTx<&'static str, String, &'static str, &'static str>> {
    let account_a = String::from("a");
    let account_b = String::from("b");

    let mut queued_a = TxQAccount::new(account_a.clone());
    queued_a.add(
        SeqProxy::sequence(5),
        MaybeTxCore::new(
            MaybeTx::new(
                Uint256::from_u64(5),
                90,
                account_a.clone(),
                Some(200),
                SeqProxy::sequence(5),
                ApplyFlags::NONE,
                parity_queueing_preflight_result(rules, SeqProxy::sequence(5)),
            ),
            TxConsequences::new(1, SeqProxy::sequence(5)),
        ),
    );

    let mut queued_b = TxQAccount::new(account_b.clone());
    queued_b.add(
        SeqProxy::sequence(8),
        MaybeTxCore::new(
            MaybeTx::new(
                Uint256::from_u64(8),
                50,
                account_b.clone(),
                Some(200),
                SeqProxy::sequence(8),
                ApplyFlags::NONE,
                parity_queueing_preflight_result(rules, SeqProxy::sequence(8)),
            ),
            TxConsequences::new(1, SeqProxy::sequence(8)),
        ),
    );

    QueueViews::new(
        std::collections::BTreeMap::from([
            (account_a.clone(), queued_a),
            (account_b.clone(), queued_b),
        ]),
        vec![
            FeeQueueEntry::new(
                FeeQueueKey::new(account_a, SeqProxy::sequence(5)),
                QueueAdvanceCandidate {
                    fee_level: 90,
                    tx_id: Uint256::from_u64(5),
                    seq_proxy: SeqProxy::sequence(5),
                },
            ),
            FeeQueueEntry::new(
                FeeQueueKey::new(account_b, SeqProxy::sequence(8)),
                QueueAdvanceCandidate {
                    fee_level: 50,
                    tx_id: Uint256::from_u64(8),
                    seq_proxy: SeqProxy::sequence(8),
                },
            ),
        ],
    )
}

fn parity_build_full_queue_owner_shell(
    rules: &Rules,
) -> QueueApplyOwnerShell<String, &'static str, &'static str, &'static str> {
    QueueApplyOwnerShell::new(QueueApplyLiveOwner::new(
        2,
        10,
        25,
        Some(2),
        OrderCandidates::new(Uint256::from_u64(0)),
        parity_build_full_queue_views(rules),
    ))
}

fn parity_build_direct_owner_shell()
-> QueueApplyOwnerShell<String, &'static str, &'static str, &'static str> {
    QueueApplyOwnerShell::new(QueueApplyLiveOwner::new(
        2,
        10,
        25,
        Some(10),
        OrderCandidates::new(Uint256::from_u64(0)),
        QueueViews::new(std::collections::BTreeMap::new(), Vec::new()),
    ))
}

