#[test]
fn txq_apply_owner_shell_after_preflight_log_sinks_match_live_owner_wrapper_member_boundary() {
    let rules = Rules::new(std::iter::empty());
    let account_id = String::from("a");
    let tx_source = ParityObservedTxSource {
        account: &account_id,
        transaction_id: "ABC123",
        tx_id: Uint256::from_u64(9),
        tx_seq_proxy: SeqProxy::sequence(5),
    };
    let view_source = parity_direct_view(&rules);
    let preflight_result = parity_queueing_preflight_result(&rules, SeqProxy::sequence(5));

    let mut live_owner = parity_build_direct_owner_shell().owner().clone();
    let live_emitted = RefCell::new(Vec::new());
    let live_stage = run_queue_apply_after_preflight_with_live_owner_from_sources_and_log_sinks(
        &mut live_owner,
        &tx_source,
        &view_source,
        &preflight_result,
        QueueHoldPreflight::new(false, false, ApplyFlags::NONE, Some(250)),
        Ter::TES_SUCCESS,
        |message| live_emitted.borrow_mut().push(format!("trace:{message}")),
        |message| live_emitted.borrow_mut().push(format!("debug:{message}")),
        |message| live_emitted.borrow_mut().push(format!("info:{message}")),
        || ApplyResult::new(Ter::TES_SUCCESS, true, true),
        |_| true,
        |_preclaim_view| {
            PreclaimResult::new(
                100,
                "tx",
                None::<&str>,
                ApplyFlags::NONE,
                "journal",
                Ter::TES_SUCCESS,
            )
        },
        || -> ApplyResult { unreachable!("direct apply path should not hit try-clear") },
        || unreachable!("direct apply path should not hit sandbox apply"),
    );

    let mut shell = parity_build_direct_owner_shell();
    let shell_emitted = RefCell::new(Vec::new());
    let shell_stage = shell.apply_after_preflight_with_log_sinks(
        &tx_source,
        &view_source,
        &preflight_result,
        QueueHoldPreflight::new(false, false, ApplyFlags::NONE, Some(250)),
        Ter::TES_SUCCESS,
        |message| shell_emitted.borrow_mut().push(format!("trace:{message}")),
        |message| shell_emitted.borrow_mut().push(format!("debug:{message}")),
        |message| shell_emitted.borrow_mut().push(format!("info:{message}")),
        || ApplyResult::new(Ter::TES_SUCCESS, true, true),
        |_| true,
        |_preclaim_view| {
            PreclaimResult::new(
                100,
                "tx",
                None::<&str>,
                ApplyFlags::NONE,
                "journal",
                Ter::TES_SUCCESS,
            )
        },
        || -> ApplyResult { unreachable!("direct apply path should not hit try-clear") },
        || unreachable!("direct apply path should not hit sandbox apply"),
    );

    let expected_emitted = vec![
        format!("trace:{}", format_direct_apply_start_log_message("ABC123")),
        format!(
            "trace:{}",
            format_direct_apply_finish_log_message(&DirectApplyExecution::<String, _> {
                transaction_id: "ABC123",
                attempt: DirectApplyAttemptResult {
                    apply_result: ApplyResult::new(Ter::TES_SUCCESS, true, true),
                    removed_replacement: None,
                },
            })
        ),
    ];
    let live_emitted = live_emitted.into_inner();
    let shell_emitted = shell_emitted.into_inner();

    assert_eq!(shell_stage, live_stage);
    assert_eq!(shell.owner(), &live_owner);
    assert_eq!(shell_emitted, live_emitted);
    assert_eq!(shell_emitted, expected_emitted);
}

#[test]
fn txq_apply_lock_scope_owner_app_view_method_matches_owner_shell_lock_region() {
    #[derive(Default)]
    struct TestApp {
        preflight_calls: usize,
        trace_messages: Vec<String>,
        direct_apply_calls: usize,
        prepare_multitxn_calls: usize,
        preclaim_calls: usize,
        try_clear_calls: usize,
        apply_sandbox_calls: usize,
    }

    impl tx::QueueApplyExecutionRuntime<&'static str, &'static str, &'static str> for TestApp {
        fn run_preflight(
            &mut self,
        ) -> PreflightResult<&'static str, TxConsequences, &'static str, &'static str> {
            self.preflight_calls += 1;
            PreflightResult::new(
                "tx",
                None::<&str>,
                Rules::new(std::iter::empty()),
                TxConsequences::with_category(
                    1,
                    SeqProxy::sequence(6),
                    TxConsequencesCategory::Blocker,
                ),
                ApplyFlags::NONE,
                "journal",
                Ter::TES_SUCCESS,
            )
        }

        fn trace(&mut self, message: &str) {
            self.trace_messages.push(message.to_owned());
        }

        fn direct_apply(&mut self) -> ApplyResult {
            self.direct_apply_calls += 1;
            ApplyResult::new(Ter::TES_SUCCESS, true, true)
        }

        fn prepare_multitxn(&mut self, _adjustment: QueueApplyViewAdjustment) -> bool {
            self.prepare_multitxn_calls += 1;
            true
        }

        fn run_preclaim(
            &mut self,
            view_source: QueueApplyPreclaimViewSource,
        ) -> PreclaimResult<&'static str, &'static str, &'static str> {
            self.preclaim_calls += 1;
            assert!(!view_source.has_multi_txn());
            PreclaimResult::new(
                100,
                "tx",
                None::<&str>,
                ApplyFlags::NONE,
                "journal",
                Ter::TES_SUCCESS,
            )
        }

        fn run_try_clear(&mut self) -> ApplyResult {
            self.try_clear_calls += 1;
            ApplyResult::new(Ter::TES_SUCCESS, true, true)
        }

        fn apply_sandbox(&mut self) {
            self.apply_sandbox_calls += 1;
        }
    }

    let rules = Rules::new(std::iter::empty());
    let account_id = String::from("acct");
    let tx_source = ParityObservedTxSource {
        account: &account_id,
        transaction_id: "ABC123",
        tx_id: Uint256::from_u64(9),
        tx_seq_proxy: SeqProxy::sequence(6),
    };
    let view_source = ParityObservedViewSource {
        rules: rules.clone(),
        account_lookup: QueueApplyObservedAccountLookup::Present {
            sequence: 5,
            balance_drops: 1_000,
        },
        ticket_lookup: QueueApplyObservedTicketLookup::Present,
        calculated_base_fee_drops: 10,
        fee_paid_drops: 1,
        default_base_fee_drops: 10,
        metrics_snapshot: QueueFeeMetricsSnapshot {
            txns_expected: 32,
            escalation_multiplier: tx::TXQ_BASE_LEVEL * 500,
        },
        open_ledger_tx_count: 4,
        open_ledger_seq: 100,
        reserve_drops: 200,
        base_fee_drops: 10,
    };

    let build_views = || {
        let mut queued_account = TxQAccount::new(account_id.clone());
        queued_account.add(
            SeqProxy::sequence(5),
            MaybeTxCore::new(
                MaybeTx::new(
                    Uint256::from_u64(5),
                    90,
                    account_id.clone(),
                    Some(200),
                    SeqProxy::sequence(5),
                    ApplyFlags::NONE,
                    PreflightResult::new(
                        "tx",
                        None::<&str>,
                        rules.clone(),
                        TxConsequences::with_category(
                            1,
                            SeqProxy::sequence(5),
                            TxConsequencesCategory::Blocker,
                        ),
                        ApplyFlags::NONE,
                        "journal",
                        Ter::TES_SUCCESS,
                    ),
                ),
                TxConsequences::with_category(
                    1,
                    SeqProxy::sequence(5),
                    TxConsequencesCategory::Blocker,
                ),
            ),
        );
        QueueViews::new(
            std::collections::BTreeMap::from([(account_id.clone(), queued_account)]),
            vec![],
        )
    };

    let mut shell = QueueApplyOwnerShell::new(QueueApplyLiveOwner::new(
        2,
        10,
        25,
        Some(10),
        OrderCandidates::new(Uint256::from_u64(0)),
        build_views(),
    ));
    let mut shell_app = TestApp::default();
    let shell_stage = shell.apply_with_app_view(
        &mut shell_app,
        &view_source,
        &tx_source,
        QueueHoldPreflight::new(false, false, ApplyFlags::NONE, Some(250)),
        ApplyFlags::NONE,
        TxConsequences::with_category(1, SeqProxy::sequence(6), TxConsequencesCategory::Blocker),
        Ter::TES_SUCCESS,
    );

    let mut locked_owner =
        tx::QueueApplyLockScopeOwner::new(QueueApplyOwnerShell::new(QueueApplyLiveOwner::new(
            2,
            10,
            25,
            Some(10),
            OrderCandidates::new(Uint256::from_u64(0)),
            build_views(),
        )));
    let mut lock = ParityApplyLockScope;
    let mut locked_app = TestApp::default();
    let locked_stage = locked_owner.apply_with_app_view(
        &mut lock,
        &mut locked_app,
        &view_source,
        &tx_source,
        QueueHoldPreflight::new(false, false, ApplyFlags::NONE, Some(250)),
        ApplyFlags::NONE,
        TxConsequences::with_category(1, SeqProxy::sequence(6), TxConsequencesCategory::Blocker),
        Ter::TES_SUCCESS,
    );

    assert_eq!(locked_stage, shell_stage);
    assert_eq!(locked_owner.owner(), &shell);
    assert_eq!(locked_app.preflight_calls, 1);
    assert_eq!(locked_app.direct_apply_calls, 0);
    assert_eq!(locked_app.prepare_multitxn_calls, 0);
    assert_eq!(locked_app.preclaim_calls, 0);
    assert_eq!(locked_app.try_clear_calls, 0);
    assert_eq!(locked_app.apply_sandbox_calls, 0);
    assert!(locked_app.trace_messages.is_empty());
}

