#[test]
fn txq_apply_lock_scope_owner_app_view_caller_preclaim_matches_owner_shell_lock_region() {
    let rules = Rules::new(std::iter::empty());
    let account_id = String::from("acct");
    let tx_source = parity_flow_tx_source(&account_id);
    let view_source = parity_flow_view(&rules);
    let preflight_result = parity_flow_preflight_result(&rules);
    let expected_prepared = RefCell::new(None::<QueueApplyPreparedPreclaimInputs<String>>);

    let mut shell = parity_build_flow_owner_shell(&rules, &account_id);
    let mut shell_app = ParityCallerPreclaimApp::new(preflight_result.clone());
    let shell_stage = shell.apply_with_app_view_and_caller_preclaim(
        &mut shell_app,
        &view_source,
        &tx_source,
        QueueHoldPreflight::new(false, false, ApplyFlags::NONE, Some(250)),
        ApplyFlags::FAIL_HARD | ApplyFlags::RETRY,
        preflight_result.clone().consequences,
        Ter::TES_SUCCESS,
        |prepared| {
            expected_prepared.replace(Some(prepared.clone()));
            Ok(parity_caller_preclaim_stage(prepared, &preflight_result))
        },
    );

    let mut locked_owner = parity_build_flow_lock_scope_owner(&rules, &account_id);
    let mut lock = ParityApplyLockScope;
    let mut locked_app = ParityCallerPreclaimApp::new(preflight_result.clone());
    let locked_stage = locked_owner.apply_with_app_view_and_caller_preclaim(
        &mut lock,
        &mut locked_app,
        &view_source,
        &tx_source,
        QueueHoldPreflight::new(false, false, ApplyFlags::NONE, Some(250)),
        ApplyFlags::FAIL_HARD | ApplyFlags::RETRY,
        preflight_result.clone().consequences,
        Ter::TES_SUCCESS,
        |prepared| {
            assert_eq!(Some(prepared.clone()), *expected_prepared.borrow());
            Ok(parity_caller_preclaim_stage(prepared, &preflight_result))
        },
    );

    assert_eq!(locked_stage, shell_stage);
    assert_eq!(locked_owner.owner(), &shell);
    assert_eq!(locked_app.preflight_calls, 1);
    assert_eq!(locked_app.direct_apply_calls, 0);
    assert_eq!(locked_app.prepare_multitxn_calls, 1);
    assert_eq!(locked_app.preclaim_calls, 0);
    assert_eq!(locked_app.try_clear_calls, 0);
    assert_eq!(locked_app.apply_sandbox_calls, 0);
    assert!(locked_app.trace_messages.is_empty());
}

