#[test]
fn txq_apply_txq_log_messages_match_lock_scope_owner_member_boundary() {
    let rules = Rules::new(std::iter::empty());
    let account_id = String::from("a");
    let tx_source = ParityObservedTxSource {
        account: &account_id,
        transaction_id: "ABC123",
        tx_id: Uint256::from_u64(9),
        tx_seq_proxy: SeqProxy::sequence(6),
    };
    let view_source = parity_queueing_view(&rules);

    let mut locked_owner =
        tx::QueueApplyLockScopeOwner::new(parity_build_full_queue_owner_shell(&rules));
    let mut lock = ParityApplyLockScope;
    let mut locked_app = parity_queueing_app(&rules, SeqProxy::sequence(6));
    let locked_stage = locked_owner.apply_with_log_messages(
        &mut lock,
        &mut locked_app,
        &view_source,
        &tx_source,
        QueueHoldPreflight::new(false, false, ApplyFlags::NONE, Some(250)),
        ApplyFlags::FAIL_HARD | ApplyFlags::RETRY,
        TxConsequences::new(1, SeqProxy::sequence(6)),
        Ter::TES_SUCCESS,
    );

    let mut txq = tx::QueueApplyTxQ::new(tx::QueueApplyLockScopeOwner::new(
        parity_build_full_queue_owner_shell(&rules),
    ));
    let mut lock = ParityApplyLockScope;
    let mut txq_app = parity_queueing_app(&rules, SeqProxy::sequence(6));
    let txq_stage = txq.apply_with_log_messages(
        &mut lock,
        &mut txq_app,
        &view_source,
        &tx_source,
        QueueHoldPreflight::new(false, false, ApplyFlags::NONE, Some(250)),
        ApplyFlags::FAIL_HARD | ApplyFlags::RETRY,
        TxConsequences::new(1, SeqProxy::sequence(6)),
        Ter::TES_SUCCESS,
    );

    assert_eq!(txq_stage, locked_stage);
    assert_eq!(txq.lock_scope_owner(), &locked_owner);
    assert_eq!(txq_stage.queue_log_messages.info.len(), 1);
    assert_eq!(txq_stage.queue_log_messages.debug.len(), 1);
    assert!(txq_stage.queue_log_messages.trace.is_empty());
    assert_eq!(txq_app.preflight_calls, 1);
    assert_eq!(txq_app.direct_apply_calls, 0);
    assert_eq!(txq_app.prepare_multitxn_calls, 1);
    assert_eq!(txq_app.preclaim_calls, 1);
    assert!(txq_app.trace_messages.is_empty());
}

