#[test]
fn tx_preclaim_shell_reflights_when_rules_change() {
    let old_rules = Rules::from_ledger(
        [protocol::feature_single_asset_vault()],
        Uint256::from_array([0x11; 32]),
        std::iter::empty(),
    );
    let new_rules = Rules::from_ledger(
        [protocol::feature_single_asset_vault()],
        Uint256::from_array([0x22; 32]),
        std::iter::empty(),
    );
    let preflight = tx::PreflightResult::new(
        "tx",
        None::<&str>,
        old_rules,
        tx::TxConsequences::new(12, SeqProxy::sequence(5)),
        ApplyFlags::RETRY,
        "journal",
        Ter::TES_SUCCESS,
    );

    let result = tx::run_preclaim_with_context(
        preflight,
        "registry",
        "view",
        &new_rules,
        7,
        |_preflight, rules| {
            tx::PreflightResult::new(
                "tx",
                None::<&str>,
                rules.clone(),
                tx::TxConsequences::new(12, SeqProxy::sequence(5)),
                ApplyFlags::FAIL_HARD,
                "journal",
                Ter::TES_SUCCESS,
            )
        },
        |ctx| {
            assert_eq!(ctx.flags, ApplyFlags::FAIL_HARD);
            Ok::<_, &str>(Ter::TEC_CLAIM)
        },
    );

    assert_eq!(result.ledger_seq, 7);
    assert_eq!(result.flags, ApplyFlags::FAIL_HARD);
    assert_eq!(result.ter, Ter::TEC_CLAIM);
    assert!(result.likely_to_claim_fee);
}

