#[test]
fn tx_invoke_preflight_shell_enters_step_runtime_and_returns_dispatched_result() {
    protocol::set_current_transaction_rules(None);
    let rules = Rules::from_ledger(
        [protocol::feature_single_asset_vault()],
        basics::base_uint::Uint256::from_array([0x33; 32]),
        std::iter::empty(),
    );

    let (ter, consequences) = tx::run_invoke_preflight_with_context(&rules, || {
        assert_eq!(
            protocol::get_current_transaction_rules(),
            Some(rules.clone())
        );
        Ok::<_, tx::UnknownTransactionType<&str>>((
            Ter::TES_SUCCESS,
            tx::TxConsequences::new(12, SeqProxy::sequence(4)),
        ))
    });

    assert_eq!(ter, Ter::TES_SUCCESS);
    assert_eq!(
        consequences,
        tx::TxConsequences::new(12, SeqProxy::sequence(4))
    );
    assert_eq!(protocol::get_current_transaction_rules(), None);
}

