#[derive(Clone)]
struct TxnTypeStubSource {
    txn_type: protocol::TxType,
}

impl tx::HasTxnType for TxnTypeStubSource {
    fn txn_type(&self) -> protocol::TxType {
        self.txn_type
    }
}

#[test]
