#[test]
fn tx_apply_for_txn_type_dispatches_known_payment_apply_shell() {
    let result = tx::run_apply_for_txn_type(
        "registry",
        TxnTypeStubSource {
            txn_type: protocol::TxType::PAYMENT,
        },
        Some("batch"),
        &Rules::new(std::iter::empty()),
        ApplyFlags::BATCH,
        9,
        "base",
        vec![1_i32],
        "journal",
        protocol::TxType::PAYMENT,
        |_ctx, txn_type| {
            assert_eq!(txn_type, protocol::TxType::PAYMENT);
            Ok::<_, &str>((
                Ter::TES_SUCCESS,
                tx::TxConsequences::new(10, SeqProxy::sequence(4)),
            ))
        },
        |_ctx| unreachable!("successful dispatch should not use fallback"),
        |_ctx, txn_type| {
            assert_eq!(txn_type, protocol::TxType::PAYMENT);
            Ok::<_, &str>(Ter::TES_SUCCESS)
        },
        |_base, tx, txn_type| {
            assert_eq!(tx.txn_type, protocol::TxType::PAYMENT);
            assert_eq!(txn_type, protocol::TxType::PAYMENT);
            12_u64
        },
        || 0_u64,
        |ctx, txn_type| {
            assert_eq!(ctx.parent_batch_id, Some("batch"));
            assert_eq!(ctx.base_fee, 12_u64);
            assert_eq!(txn_type, protocol::TxType::PAYMENT);
            Ok::<_, &str>(tx::ApplyResult::new(Ter::TES_SUCCESS, true, true))
        },
    );

    assert_eq!(result, tx::ApplyResult::new(Ter::TES_SUCCESS, true, true));
}

#[test]
fn tx_apply_for_txn_source_uses_current_rules_for_preflight_apply_shell() {
    let rules = Rules::from_ledger(
        [protocol::feature_single_asset_vault()],
        basics::base_uint::Uint256::from_array([0x62; 32]),
        std::iter::empty(),
    );
    let preflight_calls = std::cell::Cell::new(0_u32);

    let result = tx::run_apply_for_txn_source(
        "registry",
        TxnTypeStubSource {
            txn_type: protocol::TxType::PAYMENT,
        },
        None::<&str>,
        &rules,
        ApplyFlags::FAIL_HARD,
        9,
        "base",
        "view",
        "journal",
        |ctx, txn_type| {
            let next_call = preflight_calls.get() + 1;
            preflight_calls.set(next_call);
            assert_eq!(ctx.rules, rules);
            assert_eq!(txn_type, protocol::TxType::PAYMENT);
            Ok::<_, &str>((
                Ter::TES_SUCCESS,
                tx::TxConsequences::new(8, SeqProxy::sequence(2)),
            ))
        },
        |_ctx| unreachable!("successful dispatch should not use fallback"),
        |_ctx, txn_type| {
            assert_eq!(txn_type, protocol::TxType::PAYMENT);
            Ok::<_, &str>(Ter::TES_SUCCESS)
        },
        |_base, _tx, txn_type| {
            assert_eq!(txn_type, protocol::TxType::PAYMENT);
            11_u64
        },
        || 0_u64,
        |ctx, txn_type| {
            assert_eq!(ctx.base_fee, 11_u64);
            assert_eq!(txn_type, protocol::TxType::PAYMENT);
            Ok::<_, &str>(tx::ApplyResult::new(Ter::TES_SUCCESS, true, true))
        },
    );

    assert_eq!(result, tx::ApplyResult::new(Ter::TES_SUCCESS, true, true));
    assert_eq!(preflight_calls.get(), 1);
}

#[test]
fn tx_apply_for_txn_source_maps_hook_set_to_temunknown_apply_shell() {
    let result = tx::run_apply_for_txn_source(
        "registry",
        TxnTypeStubSource {
            txn_type: protocol::TxType::HOOK_SET,
        },
        None::<&str>,
        &Rules::new(std::iter::empty()),
        ApplyFlags::NONE,
        9,
        "base",
        "view",
        "journal",
        |_ctx, _txn_type| -> Result<(Ter, tx::TxConsequences), &str> {
            unreachable!("hook set should not dispatch")
        },
        |_ctx| unreachable!("unknown type should not use exception fallback"),
        |_ctx, _txn_type| -> Result<Ter, &str> {
            unreachable!("failed preflight should skip preclaim dispatch")
        },
        |_base, _tx, _txn_type| unreachable!("failed preflight should skip fee calculation"),
        || 0_u64,
        |_ctx, _txn_type| -> Result<tx::ApplyResult, &str> {
            unreachable!("failed preflight should skip apply dispatch")
        },
    );

    assert_eq!(
        result,
        tx::ApplyResult::new(tx::UNKNOWN_TRANSACTION_TYPE_TER, false, false)
    );
}

#[test]
fn tx_apply_transaction_flow_for_txn_type_classifies_success_shell() {
    let result = tx::run_apply_transaction_flow_for_txn_type(
        "registry",
        TxnTypeStubSource {
            txn_type: protocol::TxType::PAYMENT,
        },
        None::<&str>,
        &Rules::new(std::iter::empty()),
        true,
        ApplyFlags::FAIL_HARD,
        9,
        "base",
        "view",
        "journal",
        protocol::TxType::PAYMENT,
        |_ctx, txn_type| {
            assert_eq!(txn_type, protocol::TxType::PAYMENT);
            Ok::<_, &str>((
                Ter::TES_SUCCESS,
                tx::TxConsequences::new(9, SeqProxy::sequence(3)),
            ))
        },
        |_ctx| unreachable!("successful dispatch should not use fallback"),
        |_ctx, txn_type| {
            assert_eq!(txn_type, protocol::TxType::PAYMENT);
            Ok::<_, &str>(Ter::TES_SUCCESS)
        },
        |_base, _tx, txn_type| {
            assert_eq!(txn_type, protocol::TxType::PAYMENT);
            12_u64
        },
        || 0_u64,
        |_ctx, txn_type| {
            assert_eq!(txn_type, protocol::TxType::PAYMENT);
            Ok::<_, &str>(tx::ApplyResult::new(Ter::TES_SUCCESS, true, true))
        },
    );

    assert_eq!(result, tx::ApplyTransactionResult::Success);
}

