#[test]
fn tx_preflight_for_txn_source_dispatches_known_payment_public_shell() {
    protocol::set_current_transaction_rules(None);
    let rules = Rules::from_ledger(
        [protocol::feature_single_asset_vault()],
        basics::base_uint::Uint256::from_array([0x46; 32]),
        std::iter::empty(),
    );

    let result = tx::run_preflight_for_txn_source(
        tx::PreflightContext::<&str, TxnTypeStubSource, &str, ()>::new(
            "registry",
            TxnTypeStubSource {
                txn_type: protocol::TxType::PAYMENT,
            },
            rules.clone(),
            ApplyFlags::RETRY,
            "journal",
        ),
        |ctx, txn_type| {
            assert_eq!(ctx.tx.txn_type, protocol::TxType::PAYMENT);
            assert_eq!(txn_type, protocol::TxType::PAYMENT);
            assert_eq!(
                protocol::get_current_transaction_rules(),
                Some(rules.clone())
            );
            Ok::<_, &str>((
                Ter::TES_SUCCESS,
                tx::TxConsequences::new(9, SeqProxy::sequence(3)),
            ))
        },
        |_ctx| unreachable!("successful dispatch should not use fallback"),
    );

    assert_eq!(result.ter, Ter::TES_SUCCESS);
    assert_eq!(
        result.consequences,
        tx::TxConsequences::new(9, SeqProxy::sequence(3))
    );
    assert_eq!(protocol::get_current_transaction_rules(), None);
}

