#[test]
fn tx_preclaim_for_txn_source_dispatches_known_payment_public_shell() {
    protocol::set_current_transaction_rules(None);
    let rules = Rules::from_ledger(
        [protocol::feature_single_asset_vault()],
        basics::base_uint::Uint256::from_array([0x47; 32]),
        std::iter::empty(),
    );

    let result = tx::run_preclaim_for_txn_source(
        tx::PreflightResult::new(
            TxnTypeStubSource {
                txn_type: protocol::TxType::PAYMENT,
            },
            None::<&str>,
            rules.clone(),
            tx::TxConsequences::new(12, SeqProxy::sequence(5)),
            ApplyFlags::FAIL_HARD,
            "journal",
            Ter::TES_SUCCESS,
        ),
        "registry",
        "view",
        &rules,
        7,
        |_preflight, _rules| unreachable!("matching rules should skip reflight"),
        |ctx, txn_type| {
            assert_eq!(ctx.tx.txn_type, protocol::TxType::PAYMENT);
            assert_eq!(txn_type, protocol::TxType::PAYMENT);
            assert_eq!(
                protocol::get_current_transaction_rules(),
                Some(rules.clone())
            );
            Ok::<_, &str>(Ter::TEC_CLAIM)
        },
    );

    assert_eq!(result.ledger_seq, 7);
    assert_eq!(result.ter, Ter::TEC_CLAIM);
    assert!(result.likely_to_claim_fee);
    assert_eq!(protocol::get_current_transaction_rules(), None);
}

