#[test]
fn tx_do_apply_for_txn_source_dispatches_known_payment_public_shell() {
    protocol::set_current_transaction_rules(None);
    let rules = Rules::from_ledger(
        [protocol::feature_single_asset_vault()],
        basics::base_uint::Uint256::from_array([0x48; 32]),
        std::iter::empty(),
    );

    let result = tx::run_do_apply_for_txn_source(
        tx::PreclaimResult::new(
            9,
            TxnTypeStubSource {
                txn_type: protocol::TxType::PAYMENT,
            },
            Some("batch"),
            ApplyFlags::BATCH,
            "journal",
            Ter::TES_SUCCESS,
        ),
        &rules,
        "registry",
        9,
        String::from("base"),
        vec![1_i32],
        |base, tx_source, txn_type| {
            assert_eq!(base, "base");
            assert_eq!(tx_source.txn_type, protocol::TxType::PAYMENT);
            assert_eq!(txn_type, protocol::TxType::PAYMENT);
            12_u64
        },
        || 0_u64,
        |ctx, txn_type| {
            assert_eq!(ctx.tx.txn_type, protocol::TxType::PAYMENT);
            assert_eq!(txn_type, protocol::TxType::PAYMENT);
            assert_eq!(ctx.base_fee, 12_u64);
            assert_eq!(
                protocol::get_current_transaction_rules(),
                Some(rules.clone())
            );
            Ok::<_, &str>(tx::ApplyResult::new(Ter::TES_SUCCESS, true, true))
        },
    );

    assert_eq!(result, tx::ApplyResult::new(Ter::TES_SUCCESS, true, true));
    assert_eq!(protocol::get_current_transaction_rules(), None);
}

